import {
  DestroyRef,
  Injectable,
  computed,
  inject,
  signal,
} from '@angular/core';

import { TableLazyLoadEvent } from 'primeng/table';
import { catchError, EMPTY } from 'rxjs';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

import {
  GridConfiguration,
  GridDataService,
  DataGridParams,
  GridColumn,
  FilterCriteria,
  FilterValue,
  DATE_FORMATS,
} from '../../../shared/models';
import { UtilityService } from '../../../core/services/utility.service';
import { GridBaseService } from '../../../shared/services/grid-base.service';
import { isDefined } from '../../../shared/utils';
import { UsersDataAdapter } from '../services/adapters';
import { UserListItem, EntitiesService } from '../../../api';
import { DEFAULT_PAGE_SIZE } from '../../../core/models';
import { MeasurementDateTimeService } from '../../../shared/services/measurement-units/measurement-date-time.service';
import { DynamicDialogRef, DialogService } from 'primeng/dynamicdialog';
import { UserCreateWizardComponent } from '../components/users/user-create-wizard/user-create-wizard.component';
import { TranslateService } from '@ngx-translate/core';
import { LanguageService } from '../../../core/services/language.service';
import { cloneDeepWith } from 'lodash-es';

@Injectable({
  providedIn: 'root',
})
export class UsersGridConfig implements GridConfiguration<UserListItem> {
  private readonly usersService = inject(UsersDataAdapter);
  private readonly utilityService = inject(UtilityService);
  private readonly gridBaseService = inject(GridBaseService);
  private readonly entitiesService = inject(EntitiesService);
  private dialogRef: DynamicDialogRef | null = null;
  private readonly dialogService = inject(DialogService);
  private readonly measurementDateTimeService = inject(
    MeasurementDateTimeService,
  );
  private readonly translate = inject(TranslateService);
  private readonly languageService = inject(LanguageService);

  private readonly defaultStateValues = ['active', 'suspended', 'inactive'];
  private readonly filterState = signal<Record<string, FilterCriteria>>({
    state: {
      value: this.defaultStateValues,
      operator: 'in',
    },
  });
  private params: Record<string, string> = {};
  private readonly destroyRef = inject(DestroyRef);

  private readonly rqlFilter = computed(() =>
    this.utilityService.constructRqlFilter(this.filterState()),
  );
  private readonly fieldTransformations: Record<string, string> = {
    costCentre: 'costCentre.id',
  };

  private readonly baseColumns: GridColumn<UserListItem>[] =
    this.buildColumns();
  columns: GridColumn<UserListItem>[] = [];
  readonly columnsSignal = computed(() => {
    this.languageService.currentLanguage();
    return this.buildColumns();
  });
  dataService: GridDataService<UserListItem> = this.usersService;
  ownerId = '';
  entityType = 'users';

  private buildColumns(): GridColumn<UserListItem>[] {
    return [
      {
        field: 'name',
        header: this.translate.instant('ADMIN.USERS.GRID.NAME'),
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
        transform: 'text-ellipsis',
      },
      {
        field: 'emailAddress',
        header: this.translate.instant('ADMIN.USERS.GRID.EMAIL_ADDRESS'),
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
        transform: 'text-ellipsis',
      },
      {
        field: 'mobile',
        header: this.translate.instant('ADMIN.USERS.GRID.MOBILE_NUMBER'),
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
        transform: 'text-ellipsis',
      },
      {
        field: 'state',
        header: this.translate.instant('ADMIN.USERS.GRID.STATE'),
        filter: true,
        filterType: 'multiselect',
        filterMatchMode: 'in',
        filterConfig: {
          type: 'multiselect',
          options: [
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.ACTIVE'),
              value: 'active',
            },
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.SUSPENDED'),
              value: 'suspended',
            },
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.DELETED'),
              value: 'deleted',
            },
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.INACTIVE'),
              value: 'inactive',
            },
          ],
          defaultSelected: this.defaultStateValues,
        },
        transform: 'capitalize',
      },
      {
        field: 'costCentre',
        header: this.translate.instant('ADMIN.USERS.GRID.COST_CENTRE'),
        valueGetter: (rowData: UserListItem) =>
          isDefined(rowData.costCentre?.name) ? rowData.costCentre?.name : '',
        filter: true,
        filterType: 'multiselect',
        filterMatchMode: 'in',
        filterConfig: {
          type: 'multiselect',
          options: [],
        },
      },

      {
        field: 'timeZoneId',
        header: this.translate.instant('ADMIN.USERS.GRID.TIMEZONE'),
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
        transform: 'text-ellipsis',
      },
      {
        field: 'language',
        header: this.translate.instant('ADMIN.USERS.GRID.LANGUAGE'),
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
        transform: 'text-ellipsis',
      },
      {
        field: 'modifiedDate',
        header: this.translate.instant('ADMIN.USERS.GRID.MODIFIED'),
        filter: false,
        valueGetter: (rowData: UserListItem) =>
          isDefined(rowData.modifiedDate)
            ? this.measurementDateTimeService.formatDateTime(
                this.measurementDateTimeService.createDateAssumingUtc(
                  rowData.modifiedDate,
                ),
                DATE_FORMATS.DATE_TIME_SECONDS,
              )
            : '',
      },
    ];
  }

  getFilters(): Record<string, FilterCriteria> {
    return this.filterState();
  }

  clearFilters(): void {
    this.filterState.set({
      state: {
        value: this.defaultStateValues,
        operator: 'in',
      },
    });
  }

  initialize(params: Record<string, string>): void {
    this.params = params;
    let isClientContext = false;

    // Reset columns to the base definition (deep copy to avoid modifying baseColumns)
    this.columns = cloneDeepWith(this.baseColumns, (value) => {
      if (typeof value === 'function') {
        return value;
      }
      // Let lodash handle other types
      return undefined;
    });

    if (isDefined(this.params['clientId'])) {
      this.ownerId = String(this.params['clientId']);
      isClientContext = true;
    } else if (isDefined(this.params['vendorId'])) {
      this.ownerId = String(this.params['vendorId']);
    } else if (isDefined(this.params['distributorId'])) {
      this.ownerId = String(this.params['distributorId']);
    } else if (isDefined(this.params['superAdminId'])) {
      this.ownerId = String(this.params['superAdminId']);
    }

    if (isClientContext) {
      // Client context: costCentre column is relevant, load its filter options.
      this.loadFilterOptions();
    } else {
      // Not a client context: remove the costCentre column from the current set.
      this.columns = this.columns.filter((col) => col.field !== 'costCentre');
    }
  }

  getTitle(): string {
    return this.translate.instant('ADMIN.USERS.TITLE');
  }

  getRequestParams(event?: TableLazyLoadEvent): DataGridParams {
    let sortField = 'name:asc'; // Default

    if (isDefined(event?.sortField)) {
      const sortOrder = event.sortOrder === 1 ? 'asc' : 'desc';
      sortField = `${event.sortField}:${sortOrder}`;
    }

    return {
      owner: this.ownerId,
      offset: isDefined(event?.first) ? event.first : 0,
      recurse: false,
      limit: isDefined(event?.rows) ? event.rows : DEFAULT_PAGE_SIZE,
      sortField: sortField,
      filters: this.rqlFilter(),
    };
  }

  onFilterChange(field: string, value: FilterValue): void {
    const actualField = this.fieldTransformations[field] || field;
    const column = this.columns.find((col) => col.field === field);

    if (Array.isArray(value)) {
      const newFilters = this.gridBaseService.handleFilters(
        this.filterState(),
        actualField,
        value,
        undefined,
        column?.filterMatchMode,
      );

      this.filterState.set(newFilters);
      return;
    }

    // For non-array values, use the grid base service
    const newFilters = this.gridBaseService.handleFilters(
      this.filterState(),
      actualField,
      value,
      undefined,
      column?.filterMatchMode,
    );

    this.filterState.set(newFilters);
  }

  private loadFilterOptions(): void {
    this.entitiesService
      .listCostCentres(this.ownerId)
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        catchError(() => {
          return EMPTY;
        }),
      )
      .subscribe((costCentres) => {
        const costCentreColumn = this.columns.find(
          (col) => col.field === 'costCentre',
        );
        if (costCentreColumn?.filterConfig) {
          costCentreColumn.filterConfig.options = costCentres.items
            .map((costCentre) => ({
              label: costCentre.name ?? '',
              value: costCentre.id,
            }))
            .sort((a, b) => a.label.localeCompare(b.label));
        }
      });
  }

  onAdd(): void {
    const clientId = this.ownerId;

    this.openUserCreationDialog(clientId).subscribe((createdUser) => {
      if (isDefined(createdUser)) {
        // Refresh your user list or take any other necessary actions
        // this.refreshUsers();
      }
    });
  }

  openUserCreationDialog(ownerId: string) {
    this.dialogRef = this.dialogService.open(UserCreateWizardComponent, {
      header: this.translate.instant('SHARED.COMMON.WIZARD.TITLE', {
        entity: this.translate.instant('ADMIN.ENTITIES.USER'),
      }),
      contentStyle: { overflow: 'auto' },
      baseZIndex: 10000,
      data: { ownerId: ownerId },
      position: 'top',
      modal: true,
    });

    return (this.dialogRef as DynamicDialogRef).onClose;
  }
}
