import {
  DestroyRef,
  Injectable,
  computed,
  inject,
  signal,
} from '@angular/core';

import { TableLazyLoadEvent } from 'primeng/table';

import {
  GridConfiguration,
  GridDataService,
  DataGridParams,
  GridColumn,
  FilterCriteria,
  FilterValue,
  DATE_FORMATS,
} from '../../../shared/models';
import { UtilityService } from '../../../core/services/utility.service';
import { GridBaseService } from '../../../shared/services/grid-base.service';
import { isDefined, isNullOrUndefined } from '../../../shared/utils';
import { ClientsDataAdapter } from '../services/adapters';
import { AccountsService, ClientListItem } from '../../../api';
import { DEFAULT_PAGE_SIZE } from '../../../core/models';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { catchError, EMPTY } from 'rxjs';
import { MeasurementDateTimeService } from '../../../shared/services/measurement-units/measurement-date-time.service';
import { DynamicDialogRef, DialogService } from 'primeng/dynamicdialog';
import { VendorClientCreateWizardComponent } from '../components/vendor-clients/vendor-client-create-wizard/vendor-client-create-wizard.component';
import { AdminStateService } from '../services/state/admin-state.service';
import { TranslateService } from '@ngx-translate/core';
import { LanguageService } from '../../../core/services/language.service';

@Injectable({
  providedIn: 'root',
})
export class ClientsGridConfig implements GridConfiguration<ClientListItem> {
  private readonly clientsService = inject(ClientsDataAdapter);
  private readonly utilityService = inject(UtilityService);
  private readonly gridBaseService = inject(GridBaseService);
  private readonly accountsService = inject(AccountsService);
  private readonly measurementDateTimeService = inject(
    MeasurementDateTimeService,
  );
  private dialogRef: DynamicDialogRef | null = null;
  private readonly dialogService = inject(DialogService);
  private readonly adminState = inject(AdminStateService);
  private readonly translate = inject(TranslateService);
  private readonly languageService = inject(LanguageService);

  private readonly destroyRef = inject(DestroyRef);
  private readonly defaultStateValues = [
    ClientListItem.StateEnum.Active,
    ClientListItem.StateEnum.Inactive,
    ClientListItem.StateEnum.Suspended,
  ];
  private readonly filterState = signal<Record<string, FilterCriteria>>({
    state: {
      value: this.defaultStateValues,
      operator: 'in',
    },
  });
  private params: Record<string, string> = { vendorId: '' };

  private readonly rqlFilter = computed(() =>
    this.utilityService.constructRqlFilter(this.filterState()),
  );

  entityType = 'clients';
  columns: GridColumn<ClientListItem>[] = this.buildColumns();
  readonly columnsSignal = computed(() => {
    this.languageService.currentLanguage();
    return this.buildColumns();
  });

  dataService: GridDataService<ClientListItem> = this.clientsService;
  clientGroupTypes: { label: string; value: string }[] = [];

  private buildColumns(): GridColumn<ClientListItem>[] {
    return [
      {
        field: 'name',
        header: this.translate.instant('ADMIN.CLIENTS.GRID.NAME'),
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
      },
      {
        field: 'website',
        header: this.translate.instant('ADMIN.CLIENTS.GRID.WEBSITE'),
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
      },
      {
        field: 'group',
        header: this.translate.instant('ADMIN.CLIENTS.GRID.GROUP'),
        valueGetter: (rowData: ClientListItem) => {
          if (isNullOrUndefined(rowData.group))
            return this.translate.instant('SHARED.COMMON.NONE');

          const value = this.clientGroupTypes.find(
            (group) => group.value === rowData.group,
          )?.label;
          return value ?? this.translate.instant('SHARED.COMMON.NONE');
        },
        filter: true,
        filterType: 'multiselect',
        filterMatchMode: 'in',
        filterConfig: {
          type: 'multiselect',
          options: [],
        },
      },
      {
        field: 'state',
        header: this.translate.instant('ADMIN.CLIENTS.GRID.STATE'),
        valueGetter: (rowData: ClientListItem) =>
          isDefined(rowData.state)
            ? this.translate.instant(
                `SHARED.COMMON.STATUS.${rowData.state.toUpperCase()}`,
              )
            : '',
        filter: true,
        filterType: 'multiselect',
        filterMatchMode: 'in',
        filterConfig: {
          type: 'multiselect',
          options: [
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.ACTIVE'),
              value: ClientListItem.StateEnum.Active,
            },
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.DELETED'),
              value: ClientListItem.StateEnum.Deleted,
            },
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.INACTIVE'),
              value: ClientListItem.StateEnum.Inactive,
            },
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.SUSPENDED'),
              value: ClientListItem.StateEnum.Suspended,
            },
          ],
          defaultSelected: this.defaultStateValues,
        },
        transform: 'capitalize',
      },
      {
        field: 'assets',
        header: this.translate.instant('ADMIN.CLIENTS.GRID.ASSETS'),
        valueGetter: (rowData: ClientListItem) =>
          isDefined(rowData.counts?.['asset']) ? rowData.counts?.['asset'] : 0,
      },
      {
        field: 'devices',
        header: this.translate.instant('ADMIN.CLIENTS.GRID.DEVICES'),
        valueGetter: (rowData: ClientListItem) =>
          isDefined(rowData.counts?.['device'])
            ? rowData.counts?.['device']
            : 0,
      },
      {
        field: 'companion-camera',
        header: this.translate.instant(
          'ADMIN.CLIENTS.GRID.COMPANION_CAMERA_DEVICES',
        ),
        valueGetter: (rowData: ClientListItem) =>
          isDefined(rowData.counts?.['companion-camera'])
            ? rowData.counts?.['companion-camera']
            : 0,
      },
      {
        field: 'users',
        header: this.translate.instant('ADMIN.CLIENTS.GRID.USERS'),
        valueGetter: (rowData: ClientListItem) =>
          isDefined(rowData.counts?.['user']) ? rowData.counts?.['user'] : 0,
      },
      {
        field: 'modifiedDate',
        header: this.translate.instant('ADMIN.CLIENTS.GRID.MODIFIED'),
        filter: false,
        valueGetter: (rowData: ClientListItem) =>
          isDefined(rowData.modifiedDate)
            ? this.measurementDateTimeService.formatDateTime(
                this.measurementDateTimeService.createDateAssumingUtc(
                  rowData.modifiedDate,
                ),
                DATE_FORMATS.DATE_TIME_SECONDS,
              )
            : '',
      },
    ];
  }

  getFilters(): Record<string, FilterCriteria> {
    return this.filterState();
  }

  clearFilters(): void {
    this.filterState.set({
      state: {
        value: this.defaultStateValues,
        operator: 'in',
      },
    });
  }

  initialize(params: Record<string, string>): void {
    this.params = params;
    this.loadFilterOptions();
  }

  getTitle(): string {
    return this.translate.instant('ADMIN.CLIENTS.TITLE');
  }

  getRequestParams(event?: TableLazyLoadEvent): DataGridParams {
    // Add sorting support
    let sortField = 'name:asc'; // Default

    if (isDefined(event?.sortField)) {
      const sortOrder = event.sortOrder === 1 ? 'asc' : 'desc';
      sortField = `${event.sortField}:${sortOrder}`;
    }

    return {
      owner: this.params['vendorId'],
      offset: isDefined(event?.first) ? event.first : 0,
      recurse: false,
      limit: isDefined(event?.rows) ? event.rows : DEFAULT_PAGE_SIZE,
      sortField: sortField,
      filters: this.rqlFilter(),
      counts: 'asset,device,companion-camera,user',
    };
  }

  onFilterChange(field: string, value: FilterValue): void {
    const actualField = field;
    const column = this.columns.find((col) => col.field === field);

    if (Array.isArray(value)) {
      const newFilters = this.gridBaseService.handleFilters(
        this.filterState(),
        actualField,
        value,
        undefined,
        column?.filterMatchMode,
      );

      this.filterState.set(newFilters);
      return;
    }

    const newFilters = this.gridBaseService.handleFilters(
      this.filterState(),
      actualField,
      value,
      undefined,
      column?.filterMatchMode,
    );

    this.filterState.set(newFilters);
  }

  private loadFilterOptions(): void {
    this.accountsService
      .listCompanyGroups(this.params['vendorId'])
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        catchError(() => {
          return EMPTY;
        }),
      )
      .subscribe((groups) => {
        const typeColumn = this.columns.find((col) => col.field === 'type');
        if (typeColumn?.filterConfig) {
          this.clientGroupTypes = groups.items
            .map((type) => ({
              label: type.name ?? '',
              value: type.id,
            }))
            .sort((a, b) => a.label.localeCompare(b.label));
          typeColumn.filterConfig.options = this.clientGroupTypes;
        }
      });
  }

  onAdd(): void {
    const ownerId = this.params['vendorId'];
    const distributorId =
      this.params['distributorId'] ?? this.adminState.getActiveContextId();

    this.openClientCreationDialog(ownerId, distributorId).subscribe(
      (createdClient) => {
        if (isDefined(createdClient)) {
          // Refresh your client list or take any other necessary actions
          // this.refreshClients();
        }
      },
    );
  }

  openClientCreationDialog(ownerId: string, distributorId?: string) {
    this.dialogRef = this.dialogService.open(
      VendorClientCreateWizardComponent,
      {
        header: this.translate.instant('SHARED.COMMON.WIZARD.TITLE', {
          entity: this.translate.instant('ADMIN.ENTITIES.CLIENT'),
        }),
        contentStyle: { overflow: 'auto' },
        baseZIndex: 10000,
        data: { ownerId: ownerId, distributorId: distributorId },
        position: 'top',
        modal: true,
      },
    );

    return (this.dialogRef as DynamicDialogRef).onClose;
  }
}
