import { CommonModule } from '@angular/common';
import {
  ChangeDetectorRef,
  Component,
  DestroyRef,
  OnInit,
  TemplateRef,
  effect,
  inject,
  signal,
  viewChild,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { ReactiveFormsModule } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { DynamicDialogRef, DynamicDialogConfig } from 'primeng/dynamicdialog';
import { finalize } from 'rxjs';
import { TranslatePipe, TranslateService } from '@ngx-translate/core';
import { LanguageService } from '../../../../../core/services/language.service';

import {
  EntitiesService,
  MapsetCreateRequest,
  MapSetResponse,
} from '../../../../../api';
import { WizardComponent } from '../../../../../shared/components/wizard/wizard.component';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { MapSetDetailsSectionComponent } from '../map-set-details-section/map-set-details-section.component';
import { Step } from '../../../../../shared/models';
import { BroadcastEventMessageService } from '../../../services/broadcast-event-messages.service';

@Component({
  selector: 'app-map-set-create-wizard',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    WizardComponent,
    ButtonModule,
    MapSetDetailsSectionComponent,
    TranslatePipe,
  ],
  templateUrl: './map-set-create-wizard.component.html',
  styleUrl: './map-set-create-wizard.component.scss',
})
export class MapSetCreateWizardComponent implements OnInit {
  mapSetDetailsStep = viewChild<
    TemplateRef<{
      $implicit: Step;
    }>
  >('mapSetDetailsStep');
  confirmationTemplate = viewChild<TemplateRef<{ $implicit: Step }>>(
    'confirmationTemplate',
  );
  private readonly cdr = inject(ChangeDetectorRef);

  // References to form components
  mapSetDetailsForm =
    viewChild<MapSetDetailsSectionComponent>('mapSetDetailsForm');

  private readonly entitiesService = inject(EntitiesService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  protected readonly destroyRef = inject(DestroyRef);
  private readonly dialogRef = inject(DynamicDialogRef);
  private readonly dialogConfig = inject(DynamicDialogConfig);
  private readonly languageService = inject(LanguageService);
  private readonly translate = inject(TranslateService);

  // MapSet model to collect data across steps
  newMapSet = signal<Partial<MapsetCreateRequest>>({});

  // Form validity state
  formIsValid = signal<boolean>(false);

  displayWizard = false;
  steps: Step[] = [];
  previousStepIndex = 0;
  currentStepIndex = 0;
  ownerId: string | null = null;
  isSubmitting = signal<boolean>(false);

  constructor() {
    effect(() => {
      const mapSetDetailsStep = this.mapSetDetailsStep();
      const confirmationTemplate = this.confirmationTemplate();
      this.languageService.currentLanguage();

      if (
        isNullOrUndefined(mapSetDetailsStep) ||
        isNullOrUndefined(confirmationTemplate)
      ) {
        return;
      }
      this.steps = [
        {
          value: 1,
          header: this.translate.instant('ADMIN.MAP_SETS.DETAILS.TITLE'),
          content: mapSetDetailsStep,
          complete: false,
          validate: () => this.mapSetDetailsForm()?.validate() ?? false,
        },
        {
          value: 2,
          header: this.translate.instant('SHARED.COMMON.DIALOG.CONFIRMATION'),
          content: confirmationTemplate,
          complete: true,
        },
      ];
    });
  }

  ngOnInit(): void {
    if (isDefined(this.dialogConfig.data)) {
      this.ownerId = this.dialogConfig.data.ownerId ?? null;

      // Initialize MapSet with ownerId
      this.newMapSet.update((current) => ({
        ...current,
        ownerId: this.ownerId ?? '',
      }));
    }
  }

  openWizard() {
    this.displayWizard = true;
    this.newMapSet.set({});
  }

  // Form validity handlers
  onDetailsFormValidityChange(isValid: boolean) {
    this.steps[0].disableNext = !isValid;
    this.formIsValid.set(isValid);
  }

  // Update the MapSet state with form data
  updateMapSetDetails(formData: Record<string, unknown>) {
    this.newMapSet.update((current) => {
      const updated = { ...current };

      Object.keys(formData).forEach((key) => {
        if (key !== 'ownerId') {
          updated[key] = formData[key];
        }
      });

      if (isNullOrUndefined(updated.ownerId)) {
        updated.ownerId = this.ownerId ?? '';
      }

      return updated;
    });
  }

  onWizardComplete(): void {
    // Process the final data from all steps
    const mapSetData = this.newMapSet() as MapsetCreateRequest;
    this.isSubmitting.set(true);

    this.entitiesService
      .createMapSet(mapSetData)
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        finalize(() => this.isSubmitting.set(false)),
      )
      .subscribe({
        next: (response: MapSetResponse) => {
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'map-set',
            operation: 'create',
            entityId: response.id,
          });
          this.dialogRef.close(response);
        },
        error: (error: Error) => {
          console.error('Error creating map set:', error);
        },
      });
  }

  // Update cancel to close dialog with no result
  onWizardCancel(): void {
    this.newMapSet.set({});
    this.dialogRef.close();
  }
}
