import { Injectable, computed, inject, signal } from '@angular/core';

import { TableLazyLoadEvent } from 'primeng/table';

import {
  GridConfiguration,
  GridDataService,
  DataGridParams,
  GridColumn,
  FilterCriteria,
  FilterValue,
  DATE_FORMATS,
} from '../../../shared/models';
import { UtilityService } from '../../../core/services/utility.service';
import { GridBaseService } from '../../../shared/services/grid-base.service';
import { isDefined, isString } from '../../../shared/utils';
import { IoTypesDataAdapter } from '../services/adapters';
import { IoTypeListItem } from '../../../api';
import { DEFAULT_PAGE_SIZE } from '../../../core/models';
import { DynamicDialogRef, DialogService } from 'primeng/dynamicdialog';
import { IoTypeCreateWizardComponent } from '../components/io-types/io-type-create-wizard/io-type-create-wizard.component';
import { MeasurementDateTimeService } from '../../../shared/services/measurement-units/measurement-date-time.service';
import { ApiSchemaService } from '../../../core/services/api-schema.service';
import { TranslateService } from '@ngx-translate/core';
import { LanguageService } from '../../../core/services/language.service';

@Injectable({
  providedIn: 'root',
})
export class IoTypesGridConfig implements GridConfiguration<IoTypeListItem> {
  private readonly ioTypesService = inject(IoTypesDataAdapter);
  private readonly utilityService = inject(UtilityService);
  private readonly gridBaseService = inject(GridBaseService);
  private readonly apiSchemaService = inject(ApiSchemaService);
  private dialogRef: DynamicDialogRef | null = null;
  private readonly dialogService = inject(DialogService);
  private readonly measurementDateTimeService = inject(
    MeasurementDateTimeService,
  );
  private readonly translate = inject(TranslateService);
  private readonly languageService = inject(LanguageService);

  private readonly defaultStateValues = [IoTypeListItem.StateEnum.Active];
  private readonly filterState = signal<Record<string, FilterCriteria>>({
    state: {
      value: this.defaultStateValues,
      operator: 'in',
    },
  });
  private params: Record<string, string> = { ownerId: '' };
  private ownerId = '';

  private readonly rqlFilter = computed(() =>
    this.utilityService.constructRqlFilter(this.filterState()),
  );

  private readonly typeTranslationKeys: Record<
    IoTypeListItem.TypeEnum,
    string
  > = {
    analog_input: 'ADMIN.DEVICES.IO_TYPES.TYPES.ANALOG_INPUT',
    camera_input: 'ADMIN.DEVICES.IO_TYPES.TYPES.CAMERA_INPUT',
    digital_input: 'ADMIN.DEVICES.IO_TYPES.TYPES.DIGITAL_INPUT',
    digital_output: 'ADMIN.DEVICES.IO_TYPES.TYPES.DIGITAL_OUTPUT',
    can_input: 'ADMIN.DEVICES.IO_TYPES.TYPES.CAN_INPUT',
    counter_input: 'ADMIN.DEVICES.IO_TYPES.TYPES.COUNTER_INPUT',
    temperature_input: 'ADMIN.DEVICES.IO_TYPES.TYPES.TEMPERATURE_INPUT',
    value_input: 'ADMIN.DEVICES.IO_TYPES.TYPES.VALUE_INPUT',
  };

  entityType = 'io-types';
  columns: GridColumn<IoTypeListItem>[] = this.buildColumns();
  readonly columnsSignal = computed(() => {
    this.languageService.currentLanguage();
    return this.buildColumns();
  });

  dataService: GridDataService<IoTypeListItem> = this.ioTypesService;

  private buildColumns(): GridColumn<IoTypeListItem>[] {
    return [
      {
        field: 'name',
        header: this.translate.instant('ADMIN.DEVICES.IO_TYPES.COLUMNS.NAME'),
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
      },
      {
        field: 'type',
        header: this.translate.instant('ADMIN.DEVICES.IO_TYPES.COLUMNS.TYPE'),
        valueGetter: (rowData: IoTypeListItem) => {
          const typeValue = this.apiSchemaService.getEntityType<
            Record<string, unknown>,
            IoTypeListItem.TypeEnum
          >(rowData, 'iotype');
          return isDefined(typeValue) && isString(typeValue)
            ? this.translate.instant(this.typeTranslationKeys[typeValue])
            : '';
        },
        filter: true,
        filterType: 'multiselect',
        filterMatchMode: 'in',
        filterConfig: {
          type: 'multiselect',
          options: [
            {
              label: this.translate.instant(
                'ADMIN.DEVICES.IO_TYPES.TYPES.DIGITAL_INPUT',
              ),
              value: IoTypeListItem.TypeEnum.DigitalInput,
            },
            {
              label: this.translate.instant(
                'ADMIN.DEVICES.IO_TYPES.TYPES.DIGITAL_OUTPUT',
              ),
              value: IoTypeListItem.TypeEnum.DigitalOutput,
            },
            {
              label: this.translate.instant(
                'ADMIN.DEVICES.IO_TYPES.TYPES.ANALOG_INPUT',
              ),
              value: IoTypeListItem.TypeEnum.AnalogInput,
            },
            {
              label: this.translate.instant(
                'ADMIN.DEVICES.IO_TYPES.TYPES.TEMPERATURE_INPUT',
              ),
              value: IoTypeListItem.TypeEnum.TemperatureInput,
            },
            {
              label: this.translate.instant(
                'ADMIN.DEVICES.IO_TYPES.TYPES.CAN_INPUT',
              ),
              value: IoTypeListItem.TypeEnum.CanInput,
            },
            {
              label: this.translate.instant(
                'ADMIN.DEVICES.IO_TYPES.TYPES.COUNTER_INPUT',
              ),
              value: IoTypeListItem.TypeEnum.CounterInput,
            },
            {
              label: this.translate.instant(
                'ADMIN.DEVICES.IO_TYPES.TYPES.CAMERA_INPUT',
              ),
              value: IoTypeListItem.TypeEnum.CameraInput,
            },
            {
              label: this.translate.instant(
                'ADMIN.DEVICES.IO_TYPES.TYPES.VALUE_INPUT',
              ),
              value: IoTypeListItem.TypeEnum.ValueInput,
            },
          ],
        },
      },
      {
        field: 'state',
        header: this.translate.instant('ADMIN.DEVICES.IO_TYPES.COLUMNS.STATE'),
        valueGetter: (rowData: IoTypeListItem) =>
          isDefined(rowData.state)
            ? this.translate.instant(
                `SHARED.COMMON.STATUS.${rowData.state.toUpperCase()}`,
              )
            : '',
        filter: true,
        filterType: 'multiselect',
        filterMatchMode: 'in',
        filterConfig: {
          type: 'multiselect',
          options: [
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.ACTIVE'),
              value: IoTypeListItem.StateEnum.Active,
            },
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.DELETED'),
              value: IoTypeListItem.StateEnum.Deleted,
            },
          ],
          defaultSelected: this.defaultStateValues,
        },
        transform: 'capitalize',
      },
      {
        field: 'modifiedDate',
        header: this.translate.instant(
          'ADMIN.DEVICES.IO_TYPES.COLUMNS.MODIFIED',
        ),
        filter: false,
        valueGetter: (rowData: IoTypeListItem) =>
          isDefined(rowData.modifiedDate)
            ? this.measurementDateTimeService.formatDateTime(
                this.measurementDateTimeService.createDateAssumingUtc(
                  rowData.modifiedDate,
                ),
                DATE_FORMATS.DATE_TIME_SECONDS_YMD,
              )
            : '',
      },
    ];
  }

  getFilters(): Record<string, FilterCriteria> {
    return this.filterState();
  }

  clearFilters(): void {
    this.filterState.set({
      state: {
        value: this.defaultStateValues,
        operator: 'in',
      },
    });
  }

  initialize(params: Record<string, string>): void {
    this.params = params;
    if (isDefined(this.params['clientId'])) {
      this.ownerId = String(this.params['clientId']);
    } else if (isDefined(this.params['vendorId'])) {
      this.ownerId = String(this.params['vendorId']);
    }
  }

  getTitle(): string {
    return this.translate.instant('ADMIN.DEVICES.IO_TYPES.TITLE');
  }

  getRequestParams(event?: TableLazyLoadEvent): DataGridParams {
    let sortField = 'name:asc'; // Default

    if (isDefined(event?.sortField)) {
      const sortOrder = event.sortOrder === 1 ? 'asc' : 'desc';
      const rawField = String(event.sortField);
      const apiField =
        rawField === 'type'
          ? this.apiSchemaService.getTypePropertyKey('iotype')
          : rawField;
      sortField = `${apiField}:${sortOrder}`;
    }

    return {
      owner: this.ownerId,
      offset: isDefined(event?.first) ? event.first : 0,
      recurse: false,
      limit: isDefined(event?.rows) ? event.rows : DEFAULT_PAGE_SIZE,
      sortField: sortField,
      filters: this.rqlFilter(),
    };
  }

  onFilterChange(field: string, value: FilterValue): void {
    const column = this.columns.find((col) => col.field === field);

    if (Array.isArray(value)) {
      const newFilters = this.gridBaseService.handleFilters(
        this.filterState(),
        field,
        value,
        undefined,
        column?.filterMatchMode,
      );

      this.filterState.set(newFilters);
      return;
    }

    const newFilters = this.gridBaseService.handleFilters(
      this.filterState(),
      field,
      value,
      undefined,
      column?.filterMatchMode,
    );

    this.filterState.set(newFilters);
  }

  onAdd(): void {
    this.openIoTypeCreationDialog(this.ownerId).subscribe();
  }

  openIoTypeCreationDialog(ownerId: string) {
    this.dialogRef = this.dialogService.open(IoTypeCreateWizardComponent, {
      header: this.translate.instant('SHARED.COMMON.WIZARD.TITLE', {
        entity: this.translate.instant('ADMIN.ENTITIES.IO_TYPE'),
      }),
      contentStyle: { overflow: 'auto' },
      baseZIndex: 10000,
      data: { ownerId: ownerId },
      position: 'top',
      modal: true,
    });

    return (this.dialogRef as DynamicDialogRef).onClose;
  }
}
