import { Injectable, computed, inject, signal } from '@angular/core';

import { TableLazyLoadEvent } from 'primeng/table';

import {
  GridConfiguration,
  GridDataService,
  DataGridParams,
  GridColumn,
  FilterCriteria,
  FilterValue,
  DATE_FORMATS,
} from '../../../shared/models';
import { UtilityService } from '../../../core/services/utility.service';
import { GridBaseService } from '../../../shared/services/grid-base.service';
import { isDefined } from '../../../shared/utils';
import { AssetTagsDataAdapter } from '../services/adapters';
import { AssetTagListItem } from '../../../api';
import { DEFAULT_PAGE_SIZE } from '../../../core/models';
import { DynamicDialogRef, DialogService } from 'primeng/dynamicdialog';
import { AssetTagCreateWizardComponent } from '../components/asset-tags/asset-tag-create-wizard/asset-tag-create-wizard.component';
import { MeasurementDateTimeService } from '../../../shared/services/measurement-units/measurement-date-time.service';
import { TranslateService } from '@ngx-translate/core';
import { LanguageService } from '../../../core/services/language.service';

@Injectable({ providedIn: 'root' })
export class AssetTagsGridConfig implements GridConfiguration<AssetTagListItem> {
  private readonly assetTagsService = inject(AssetTagsDataAdapter);
  private readonly utilityService = inject(UtilityService);
  private readonly gridBaseService = inject(GridBaseService);
  private dialogRef: DynamicDialogRef | null = null;
  private readonly dialogService = inject(DialogService);
  private readonly measurementDateTimeService = inject(
    MeasurementDateTimeService,
  );
  private readonly translate = inject(TranslateService);
  private readonly languageService = inject(LanguageService);

  private readonly defaultStateValues = [AssetTagListItem.StateEnum.Active];
  private readonly filterState = signal<Record<string, FilterCriteria>>({
    state: { value: this.defaultStateValues, operator: 'in' },
  });
  private params: Record<string, string> = { clientId: '' };

  private readonly rqlFilter = computed(() =>
    this.utilityService.constructRqlFilter(this.filterState()),
  );
  private readonly fieldTransformations: Record<string, string> = {
    tagType: 'assetTagType.name',
    asset: 'asset.name',
  };

  entityType = 'asset-tags';
  columns: GridColumn<AssetTagListItem>[] = this.buildColumns();
  readonly columnsSignal = computed(() => {
    this.languageService.currentLanguage();
    return this.buildColumns();
  });

  dataService: GridDataService<AssetTagListItem> = this.assetTagsService;

  private buildColumns(): GridColumn<AssetTagListItem>[] {
    return [
      {
        field: 'name',
        header: this.translate.instant('ADMIN.ASSET_TAGS.COLUMNS.NAME'),
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
      },
      {
        field: 'serialNumber',
        header: this.translate.instant(
          'ADMIN.ASSET_TAGS.COLUMNS.SERIAL_NUMBER',
        ),
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
      },
      {
        field: 'tagType',
        header: this.translate.instant(
          'ADMIN.ASSET_TAGS.COLUMNS.ASSET_TAG_TYPE',
        ),
        valueGetter: (rowData: AssetTagListItem) =>
          rowData.assetTagType?.name ?? '',
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
      },
      {
        field: 'mode',
        header: this.translate.instant('ADMIN.ASSET_TAGS.COLUMNS.MODE'),
        filter: true,
        filterType: 'multiselect',
        filterMatchMode: 'in',
        filterConfig: {
          type: 'multiselect',
          options: [
            {
              label: this.translate.instant('ADMIN.ASSET_TAGS.MODES.MOVABLE'),
              value: AssetTagListItem.ModeEnum.Movable,
            },
            {
              label: this.translate.instant('ADMIN.ASSET_TAGS.MODES.FIXED'),
              value: AssetTagListItem.ModeEnum.Fixed,
            },
            {
              label: this.translate.instant('ADMIN.ASSET_TAGS.MODES.STOCK'),
              value: AssetTagListItem.ModeEnum.Stock,
            },
          ],
        },
        transform: 'capitalize',
      },
      {
        field: 'state',
        header: this.translate.instant('ADMIN.ASSET_TAGS.COLUMNS.STATE'),
        valueGetter: (rowData: AssetTagListItem) =>
          isDefined(rowData.state)
            ? this.translate.instant(
                `SHARED.COMMON.STATUS.${rowData.state.toUpperCase()}`,
              )
            : '',
        filter: true,
        filterType: 'multiselect',
        filterMatchMode: 'in',
        filterConfig: {
          type: 'multiselect',
          options: [
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.ACTIVE'),
              value: AssetTagListItem.StateEnum.Active,
            },
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.DELETED'),
              value: AssetTagListItem.StateEnum.Deleted,
            },
          ],
          defaultSelected: this.defaultStateValues,
        },
      },
      {
        field: 'asset',
        header: this.translate.instant('ADMIN.ASSET_TAGS.COLUMNS.ASSET'),
        valueGetter: (rowData: AssetTagListItem) => rowData.asset?.name ?? '',
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
      },
      {
        field: 'modifiedDate',
        header: this.translate.instant('ADMIN.ASSET_TAGS.COLUMNS.MODIFIED'),
        filter: false,
        valueGetter: (rowData: AssetTagListItem) =>
          isDefined(rowData['modifiedDate'])
            ? this.measurementDateTimeService.formatDateTime(
                this.measurementDateTimeService.createDateAssumingUtc(
                  rowData['modifiedDate'],
                ),
                DATE_FORMATS.DATE_TIME_SECONDS_YMD,
              )
            : '',
      },
    ];
  }

  getFilters(): Record<string, FilterCriteria> {
    return this.filterState();
  }

  clearFilters(): void {
    this.filterState.set({
      state: { value: this.defaultStateValues, operator: 'in' },
    });
  }

  initialize(params: Record<string, string>): void {
    this.params = params;
  }

  getTitle(): string {
    return this.translate.instant('ADMIN.ASSET_TAGS.TITLE');
  }

  getRequestParams(event?: TableLazyLoadEvent): DataGridParams {
    // Add sorting support
    let sortField = 'name:asc'; // Default

    if (isDefined(event?.sortField)) {
      const sortOrder = event.sortOrder === 1 ? 'asc' : 'desc';
      sortField = `${event.sortField}:${sortOrder}`;
    }

    return {
      owner: this.params['clientId'],
      offset: isDefined(event?.first) ? event.first : 0,
      recurse: false,
      limit: isDefined(event?.rows) ? event.rows : DEFAULT_PAGE_SIZE,
      sortField: sortField,
      filters: this.rqlFilter(),
    };
  }

  onFilterChange(field: string, value: FilterValue): void {
    const actualField = this.fieldTransformations[field] || field;
    const column = this.columns.find((col) => col.field === field);

    if (Array.isArray(value)) {
      const newFilters = this.gridBaseService.handleFilters(
        this.filterState(),
        actualField,
        value,
        undefined,
        column?.filterMatchMode,
      );

      this.filterState.set(newFilters);
      return;
    }

    // For non-array values, use the grid base service
    const newFilters = this.gridBaseService.handleFilters(
      this.filterState(),
      actualField,
      value,
      undefined,
      column?.filterMatchMode,
    );

    this.filterState.set(newFilters);
  }

  onAdd(): void {
    const clientId = this.params['clientId'];

    this.openAssetTagCreationDialog(clientId).subscribe();
  }

  openAssetTagCreationDialog(ownerId: string) {
    this.dialogRef = this.dialogService.open(AssetTagCreateWizardComponent, {
      header: this.translate.instant('SHARED.COMMON.WIZARD.TITLE', {
        entity: this.translate.instant('ADMIN.ENTITIES.ASSET_TAG'),
      }),
      contentStyle: { overflow: 'auto' },
      baseZIndex: 10000,
      data: { ownerId: ownerId },
      position: 'top',
      modal: true,
    });

    return (this.dialogRef as DynamicDialogRef).onClose;
  }
}
