import { Injectable, computed, inject, signal } from '@angular/core';

import { TableLazyLoadEvent } from 'primeng/table';

import {
  GridConfiguration,
  GridDataService,
  DataGridParams,
  GridColumn,
  FilterCriteria,
  FilterValue,
  DATE_FORMATS,
} from '../../../shared/models';
import { UtilityService } from '../../../core/services/utility.service';
import { GridBaseService } from '../../../shared/services/grid-base.service';
import { isDefined } from '../../../shared/utils';
import { DistributorsDataAdapter } from '../services/adapters';
import { DistributorListItem } from '../../../api';
import { DEFAULT_PAGE_SIZE, DEFAULT_SYSTEM_ID } from '../../../core/models';
import { MeasurementDateTimeService } from '../../../shared/services/measurement-units/measurement-date-time.service';
import { DynamicDialogRef, DialogService } from 'primeng/dynamicdialog';
import { SuperAdminDistributorsCreateWizardComponent } from '../components/super-admin-distributors/super-admin-distributors-create-wizard/super-admin-distributors-create-wizard.component';
import { TranslateService } from '@ngx-translate/core';
import { LanguageService } from '../../../core/services/language.service';

@Injectable({
  providedIn: 'root',
})
export class DistributorsGridConfig implements GridConfiguration<DistributorListItem> {
  private readonly distributorsService = inject(DistributorsDataAdapter);
  private readonly utilityService = inject(UtilityService);
  private readonly gridBaseService = inject(GridBaseService);
  private readonly measurementDateTimeService = inject(
    MeasurementDateTimeService,
  );
  private dialogRef: DynamicDialogRef | null = null;
  private readonly dialogService = inject(DialogService);
  private readonly translate = inject(TranslateService);
  private readonly languageService = inject(LanguageService);

  private readonly defaultStateValues = [
    DistributorListItem.StateEnum.Active,
    DistributorListItem.StateEnum.Inactive,
    DistributorListItem.StateEnum.Suspended,
  ];
  private readonly filterState = signal<Record<string, FilterCriteria>>({
    state: {
      value: this.defaultStateValues,
      operator: 'in',
    },
  });
  private params: Record<string, string> = {};

  private readonly rqlFilter = computed(() =>
    this.utilityService.constructRqlFilter(this.filterState()),
  );

  entityType = 'distributors';
  columns: GridColumn<DistributorListItem>[] = this.buildColumns();
  readonly columnsSignal = computed(() => {
    this.languageService.currentLanguage();
    return this.buildColumns();
  });

  dataService: GridDataService<DistributorListItem> = this.distributorsService;
  distributorGroupTypes: { label: string; value: string }[] = [];

  private buildColumns(): GridColumn<DistributorListItem>[] {
    return [
      {
        field: 'name',
        header: this.translate.instant('ADMIN.DISTRIBUTORS.COLUMNS.NAME'),
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
      },
      {
        field: 'website',
        header: this.translate.instant('ADMIN.DISTRIBUTORS.COLUMNS.WEBSITE'),
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
      },
      {
        field: 'state',
        header: this.translate.instant('ADMIN.DISTRIBUTORS.COLUMNS.STATE'),
        valueGetter: (rowData: DistributorListItem) =>
          isDefined(rowData.state)
            ? this.translate.instant(
                `SHARED.COMMON.STATUS.${rowData.state.toUpperCase()}`,
              )
            : '',
        filter: true,
        filterType: 'multiselect',
        filterMatchMode: 'in',
        filterConfig: {
          type: 'multiselect',
          options: [
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.ACTIVE'),
              value: DistributorListItem.StateEnum.Active,
            },
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.DELETED'),
              value: DistributorListItem.StateEnum.Deleted,
            },
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.INACTIVE'),
              value: DistributorListItem.StateEnum.Inactive,
            },
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.SUSPENDED'),
              value: DistributorListItem.StateEnum.Suspended,
            },
          ],
          defaultSelected: this.defaultStateValues,
        },
        transform: 'capitalize',
      },
      {
        field: 'vendor',
        header: this.translate.instant('ADMIN.DISTRIBUTORS.COLUMNS.VENDOR'),
        valueGetter: (rowData: DistributorListItem) =>
          isDefined(rowData.counts?.['vendor'])
            ? rowData.counts?.['vendor']
            : 0,
      },
      {
        field: 'clients',
        header: this.translate.instant('ADMIN.DISTRIBUTORS.COLUMNS.CLIENT'),
        valueGetter: (rowData: DistributorListItem) =>
          isDefined(rowData.counts?.['client'])
            ? rowData.counts?.['client']
            : 0,
      },
      {
        field: 'assets',
        header: this.translate.instant('ADMIN.DISTRIBUTORS.COLUMNS.ASSET'),
        valueGetter: (rowData: DistributorListItem) =>
          isDefined(rowData.counts?.['asset']) ? rowData.counts?.['asset'] : 0,
      },
      {
        field: 'devices',
        header: this.translate.instant('ADMIN.DISTRIBUTORS.COLUMNS.DEVICE'),
        valueGetter: (rowData: DistributorListItem) =>
          isDefined(rowData.counts?.['device'])
            ? rowData.counts?.['device']
            : 0,
      },
      {
        field: 'companion-camera',
        header: this.translate.instant(
          'ADMIN.DISTRIBUTORS.COLUMNS.COMPANION_CAMERA',
        ),
        valueGetter: (rowData: DistributorListItem) =>
          isDefined(rowData.counts?.['companion-camera'])
            ? rowData.counts?.['companion-camera']
            : 0,
      },
      {
        field: 'users',
        header: this.translate.instant('ADMIN.DISTRIBUTORS.COLUMNS.USER'),
        valueGetter: (rowData: DistributorListItem) =>
          isDefined(rowData.counts?.['user']) ? rowData.counts?.['user'] : 0,
      },
      {
        field: 'modifiedDate',
        header: this.translate.instant('ADMIN.DISTRIBUTORS.COLUMNS.MODIFIED'),
        filter: false,
        valueGetter: (rowData: DistributorListItem) =>
          isDefined(rowData.modifiedDate)
            ? this.measurementDateTimeService.formatDateTime(
                this.measurementDateTimeService.createDateAssumingUtc(
                  rowData.modifiedDate,
                ),
                DATE_FORMATS.DATE_TIME_SECONDS_YMD,
              )
            : '',
      },
    ];
  }

  getFilters(): Record<string, FilterCriteria> {
    return this.filterState();
  }

  clearFilters(): void {
    this.filterState.set({
      state: {
        value: this.defaultStateValues,
        operator: 'in',
      },
    });
  }

  initialize(params: Record<string, string>): void {
    this.params = params;
  }

  getTitle(): string {
    return this.translate.instant('ADMIN.DISTRIBUTORS.TITLE');
  }

  getRequestParams(event?: TableLazyLoadEvent): DataGridParams {
    let sortField = 'name:asc'; // Default

    if (isDefined(event?.sortField)) {
      const sortOrder = event.sortOrder === 1 ? 'asc' : 'desc';
      sortField = `${event.sortField}:${sortOrder}`;
    }

    return {
      owner: DEFAULT_SYSTEM_ID,
      offset: isDefined(event?.first) ? event.first : 0,
      recurse: false,
      limit: isDefined(event?.rows) ? event.rows : DEFAULT_PAGE_SIZE,
      sortField: sortField,
      filters: this.rqlFilter(),
      counts: 'vendor,client,asset,device,companion-camera,user',
    };
  }

  onFilterChange(field: string, value: FilterValue): void {
    const actualField = field;
    const column = this.columns.find((col) => col.field === field);

    if (Array.isArray(value)) {
      const newFilters = this.gridBaseService.handleFilters(
        this.filterState(),
        actualField,
        value,
        undefined,
        column?.filterMatchMode,
      );

      this.filterState.set(newFilters);
      return;
    }

    const newFilters = this.gridBaseService.handleFilters(
      this.filterState(),
      actualField,
      value,
      undefined,
      column?.filterMatchMode,
    );

    this.filterState.set(newFilters);
  }

  onAdd(): void {
    const ownerId = DEFAULT_SYSTEM_ID;

    this.openDistributorCreationDialog(ownerId).subscribe(
      (createdDistributor) => {
        if (isDefined(createdDistributor)) {
          // Refresh your distributor list or take any other necessary actions
          // this.refreshDistributors();
        }
      },
    );
  }

  openDistributorCreationDialog(ownerId: string) {
    this.dialogRef = this.dialogService.open(
      SuperAdminDistributorsCreateWizardComponent,
      {
        header: this.translate.instant('SHARED.COMMON.WIZARD.TITLE', {
          entity: this.translate.instant('ADMIN.ENTITIES.DISTRIBUTOR'),
        }),
        contentStyle: { overflow: 'auto' },
        baseZIndex: 10000,
        data: { ownerId: ownerId },
        position: 'top',
        modal: true,
      },
    );

    return (this.dialogRef as DynamicDialogRef).onClose;
  }
}
