import { Injectable, computed, inject, signal } from '@angular/core';

import { TableLazyLoadEvent } from 'primeng/table';
import { DynamicDialogRef, DialogService } from 'primeng/dynamicdialog';
import { TranslateService } from '@ngx-translate/core';

import {
  GridConfiguration,
  GridDataService,
  DataGridParams,
  GridColumn,
  FilterCriteria,
  FilterValue,
} from '../../../shared/models';
import { UtilityService } from '../../../core/services/utility.service';
import { GridBaseService } from '../../../shared/services/grid-base.service';
import { LanguageService } from '../../../core/services/language.service';
import { isDefined } from '../../../shared/utils';
import { DEFAULT_PAGE_SIZE } from '../../../core/models';
import { ContactsDataAdapter } from '../services/adapters';
import { Contact } from '../../../api';
import { ContactListItem } from '../services/contacts.service';
import { ContactCreateWizardComponent } from '../components/contacts/contact-create-wizard/contact-create-wizard.component';

@Injectable({ providedIn: 'root' })
export class ContactsGridConfig implements GridConfiguration<ContactListItem> {
  private readonly contactsDataAdapter = inject(ContactsDataAdapter);
  private readonly utilityService = inject(UtilityService);
  private readonly gridBaseService = inject(GridBaseService);
  private readonly dialogService = inject(DialogService);
  private readonly translate = inject(TranslateService);
  private readonly languageService = inject(LanguageService);
  private dialogRef: DynamicDialogRef | null = null;

  private readonly filterState = signal<Record<string, FilterCriteria>>({});
  private params: Record<string, string> = { clientId: '' };

  private readonly rqlFilter = computed(() =>
    this.utilityService.constructRqlFilter(this.filterState()),
  );

  entityType = 'client-contacts';

  columns: GridColumn<ContactListItem>[] = this.buildColumns();
  readonly columnsSignal = computed(() => {
    this.languageService.currentLanguage();
    return this.buildColumns();
  });

  dataService: GridDataService<ContactListItem> = this.contactsDataAdapter;

  private buildColumns(): GridColumn<ContactListItem>[] {
    const t = (key: string) => this.translate.instant(key);
    return [
      {
        field: 'name',
        header: t('ADMIN.CONTACTS.GRID.COLUMNS.NAME'),
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
      },
      {
        field: 'type',
        header: t('ADMIN.CONTACTS.GRID.COLUMNS.TYPE'),
        filter: true,
        filterType: 'multiselect',
        filterMatchMode: 'in',
        filterConfig: {
          type: 'multiselect',
          options: Object.keys(Contact.TypeEnum).map((key) => ({
            label: t(`SHARED.CONTACTS.TYPES.${key}`),
            value: Contact.TypeEnum[key as keyof typeof Contact.TypeEnum],
          })),
        },
        transform: 'capitalize',
      },
      {
        field: 'emailAddress',
        header: t('ADMIN.CONTACTS.GRID.COLUMNS.EMAIL'),
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
      },
      {
        field: 'phoneMobile',
        header: t('ADMIN.CONTACTS.GRID.COLUMNS.MOBILE'),
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
      },
      {
        field: 'phoneOffice',
        header: t('ADMIN.CONTACTS.GRID.COLUMNS.OFFICE_PHONE'),
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
      },
      {
        field: 'notes',
        header: t('ADMIN.CONTACTS.GRID.COLUMNS.NOTES'),
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
      },
    ];
  }

  getFilters(): Record<string, FilterCriteria> {
    return this.filterState();
  }

  clearFilters(): void {
    this.filterState.set({});
  }

  initialize(params: Record<string, string>): void {
    this.params = params;
  }

  getTitle(): string {
    return this.translate.instant('ADMIN.ENTITIES.CONTACTS');
  }

  getRequestParams(event?: TableLazyLoadEvent): DataGridParams {
    let sortField = 'name:asc';
    if (isDefined(event?.sortField)) {
      const sortOrder = event.sortOrder === 1 ? 'asc' : 'desc';
      sortField = `${event.sortField}:${sortOrder}`;
    }
    return {
      owner: this.params['clientId'],
      offset: isDefined(event?.first) ? event.first : 0,
      recurse: false,
      limit: isDefined(event?.rows) ? event.rows : DEFAULT_PAGE_SIZE,
      sortField,
      filters: this.rqlFilter(),
    };
  }

  onFilterChange(field: string, value: FilterValue): void {
    const column = this.columns.find((col) => col.field === field);
    const newFilters = this.gridBaseService.handleFilters(
      this.filterState(),
      field,
      value,
      undefined,
      column?.filterMatchMode,
    );
    this.filterState.set(newFilters);
  }

  onAdd(): void {
    this.dialogRef = this.dialogService.open(ContactCreateWizardComponent, {
      header: this.translate.instant('SHARED.COMMON.WIZARD.TITLE', { entity: this.translate.instant('ADMIN.ENTITIES.CONTACT') }),
      data: { ownerId: this.params['clientId'] },
      position: 'top',
      modal: true,
      contentStyle: { overflow: 'auto' },
    });
  }
}
