import { CommonModule } from '@angular/common';
import {
  Component,
  DestroyRef,
  effect,
  inject,
  OnInit,
  output,
  ViewChild,
} from '@angular/core';
import { ActivatedRoute, RouterModule } from '@angular/router';

import { ButtonModule } from 'primeng/button';
import { CardModule } from 'primeng/card';
import { ProgressSpinnerModule } from 'primeng/progressspinner';
import { EntityDetailsService } from '../../services/entity/entity-details.service';
import { ToolbarModule } from 'primeng/toolbar';
import { DetailsConfigurationService } from '../../services/entity/entity-details-configuration.service';
import { TooltipModule } from 'primeng/tooltip';
import { ConfirmDialogModule } from 'primeng/confirmdialog';
import { ActionIcon, StateOption } from '../../models';
import { EntityDetailsStateService } from '../../services/entity/entity-details.state.service';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { DetailsComponentFactory } from '../../factories';
import { BulkSelectionService } from '../../services/bulk-selection.service';
import { TranslatePipe } from '@ngx-translate/core';
import { TruncatePipe } from '../../../../shared/pipes/truncate.pipe';
import { Popover, PopoverModule } from 'primeng/popover';
import { isDefined } from '../../../../shared/utils';

@Component({
  selector: 'app-details-panel',
  imports: [
    CommonModule,
    ButtonModule,
    ProgressSpinnerModule,
    CardModule,
    RouterModule,
    ToolbarModule,
    TooltipModule,
    ConfirmDialogModule,
    TruncatePipe,
    TranslatePipe,
    PopoverModule,
  ],

  templateUrl: './details-panel.component.html',
  styleUrl: './details-panel.component.scss',
})
export class DetailsPanelComponent implements OnInit {
  readonly detailsService = inject(EntityDetailsService);
  readonly stateService = inject(EntityDetailsStateService);
  readonly bulkSelectionService = inject(BulkSelectionService);
  private readonly detailsConfigService = inject(DetailsConfigurationService);
  private readonly destroyRef = inject(DestroyRef);
  private readonly activatedRoute = inject(ActivatedRoute);
  private readonly detailsFactory = inject(DetailsComponentFactory);
  readonly closePanel = output<void>();

  @ViewChild('statePopover') statePopover!: Popover;

  actionIcons: ActionIcon[] = [];

  // Get currently active popover
  get activePopover(): string | null {
    return this.detailsConfigService.activePopover();
  }

  // Get state options for current entity (or bulk entity type)
  get stateOptions(): StateOption[] {
    const entityType =
      this.stateService.getSelectedItemType() ||
      (this.bulkSelectionService.isBulkMode() === true
        ? ((this.bulkSelectionService.checkedItems()[0]
            ?.entityType as string) ?? '')
        : null);
    return isDefined(entityType)
      ? this.detailsConfigService.getStateOptions(entityType)
      : [];
  }

  // Get current state of the entity
  get currentState(): string {
    const entity = this.stateService.selectedItem();
    return (entity?.['state'] as string) ?? '';
  }

  // Human-readable label for the bulk selection header
  get bulkLabel(): string {
    const items = this.bulkSelectionService.checkedItems();
    const rawType = (items[0]?.entityType as string) ?? 'item';
    // Capitalise first letter and append plural s
    const label = rawType.charAt(0).toUpperCase() + rawType.slice(1);
    return `${items.length} ${label}s selected`;
  }

  constructor() {
    effect(() => {
      this.stateService.selectedItem();
      this.bulkSelectionService.checkedItems();
      this.updateActionIcons();
    });
  }

  ngOnInit() {
    // Load initial icons
    this.updateActionIcons();
  }

  updateActionIcons() {
    this.actionIcons = this.detailsConfigService.getActionIcons();
  }

  executeAction(icon: ActionIcon, event?: Event, usePopover?: boolean) {
    const isBulk = this.bulkSelectionService.isBulkMode() === true;

    const dispatch = () => {
      if (isBulk && icon.bulkAction) {
        const ids = this.bulkSelectionService
          .checkedItems()
          .map((i) => String(i.id));
        icon.bulkAction(ids);
      } else {
        icon.action();
      }
    };

    if (usePopover === true && event) {
      dispatch();
      if (this.statePopover?.overlayVisible) {
        this.statePopover.hide();
      } else {
        this.statePopover.show(event);
      }
    } else {
      dispatch();
    }
  }

  resolveTooltip(icon: ActionIcon): string {
    const isBulk = this.bulkSelectionService.isBulkMode() === true;
    if (isBulk && isDefined(icon.bulkTooltip)) {
      if (typeof icon.bulkTooltip === 'function') {
        const ids = this.bulkSelectionService
          .checkedItems()
          .map((i) => String(i.id));
        return icon.bulkTooltip(ids);
      }
      return icon.bulkTooltip;
    }
    return icon.tooltip;
  }

  togglePopover(id: string) {
    this.detailsConfigService.togglePopover(id);
  }

  // OverlayPanel handles its own positioning; no-op placeholder for future hooks

  setActivePopover(id: string | null) {
    this.detailsConfigService.setActivePopover(id);
  }

  updateState(state: string) {
    // Don't update if it's the current state already
    if (state === this.currentState) {
      this.togglePopover('changeState'); // Just close the popover
      return;
    }

    const routeEntityType = this.detailsFactory.getEntityTypeFromRoute(
      this.activatedRoute,
      'type',
    );

    const isBulk = this.bulkSelectionService.isBulkMode() === true;
    const checkedItem = this.bulkSelectionService.checkedItems()[0];
    const entityType =
      this.stateService.getSelectedItemType() ||
      String(checkedItem.entityType) ||
      routeEntityType;

    const ids = isBulk
      ? this.bulkSelectionService.checkedItems().map((i) => String(i.id))
      : [String(this.stateService.getSelectedItemId() ?? '')].filter(Boolean);

    if (isDefined(entityType) && ids.length > 0) {
      this.detailsConfigService
        .updateEntityState(entityType, ids, state)
        .pipe(takeUntilDestroyed(this.destroyRef))
        .subscribe();
    }
  }

  onClosePanel() {
    this.detailsService.closeDetailsPanel();
    this.closePanel.emit();
  }
}
