import { Injectable, computed, inject, signal } from '@angular/core';

import { TableLazyLoadEvent } from 'primeng/table';
import { forkJoin, of } from 'rxjs';
import { catchError, finalize, tap } from 'rxjs/operators';
import { MessageService } from 'primeng/api';

import {
  GridConfiguration,
  GridDataService,
  DataGridParams,
  GridColumn,
  FilterCriteria,
  FilterValue,
  DATE_FORMATS,
} from '../../../shared/models';
import { UtilityService } from '../../../core/services/utility.service';
import { GridBaseService } from '../../../shared/services/grid-base.service';
import { isDefined } from '../../../shared/utils';
import { AlertsDataAdapter } from '../services/adapters';
import { DEFAULT_PAGE_SIZE } from '../../../core/models';
import { MeasurementDateTimeService } from '../../../shared/services/measurement-units/measurement-date-time.service';
import { DynamicDialogRef, DialogService } from 'primeng/dynamicdialog';
import { AlertCreateWizardComponent } from '../components/alerts/alert-create-wizard/alert-create-wizard.component';
import { AdminDataService } from '../services/admin-data.service';
import { VendorAlertPickerComponent } from '../components/alerts/vendor-alert-picker/vendor-alert-picker.component';
import {
  ExtendedAlertListItem,
  ExtendedAlertCreateRequest,
} from '../models/alerts.model';
import { AlertsService, AlertListItem, AlertResponse } from '../../../api';
import { BroadcastEventMessageService } from '../services/broadcast-event-messages.service';
import { TranslateService } from '@ngx-translate/core';
import { LanguageService } from '../../../core/services/language.service';

@Injectable({
  providedIn: 'root',
})
export class AlertsGridConfig implements GridConfiguration<ExtendedAlertListItem> {
  private readonly alertsService = inject(AlertsDataAdapter);
  private readonly utilityService = inject(UtilityService);
  private readonly gridBaseService = inject(GridBaseService);
  private readonly adminDataService = inject(AdminDataService);
  private readonly entitiesService = inject(AlertsService);
  private dialogRef: DynamicDialogRef | null = null;
  private readonly dialogService = inject(DialogService);
  private readonly messageService = inject(MessageService);
  private readonly measurementDateTimeService = inject(
    MeasurementDateTimeService,
  );
  private readonly broadcastService = inject(BroadcastEventMessageService);
  private readonly translate = inject(TranslateService);
  private readonly languageService = inject(LanguageService);
  private readonly refreshTrigger = signal<number>(0);

  private readonly defaultStateValues = [AlertListItem.StateEnum.Active];
  private readonly filterState = signal<Record<string, FilterCriteria>>({
    state: {
      value: this.defaultStateValues,
      operator: 'in',
    },
  });
  private params: Record<string, string> = { clientId: '' };

  private readonly rqlFilter = computed(() =>
    this.utilityService.constructRqlFilter(this.filterState()),
  );
  private readonly fieldTransformations: Record<string, string> = {
    costCentre: 'costCentre.id',
  };
  private readonly priorityLabels: Record<AlertListItem.PriorityEnum, string> =
    {
      high: this.translate.instant('ADMIN.ALERTS.PRIORITIES.HIGH'),
      medium: this.translate.instant('ADMIN.ALERTS.PRIORITIES.MEDIUM'),
      low: this.translate.instant('ADMIN.ALERTS.PRIORITIES.LOW'),
    };

  entityType = 'alerts';
  bulkImportIcon?: string;
  bulkImportLabel?: string;
  onBulkImport?: () => void;

  columns: GridColumn<ExtendedAlertListItem>[] = this.buildColumns();
  readonly columnsSignal = computed(() => {
    this.languageService.currentLanguage();
    return this.buildColumns();
  });

  dataService: GridDataService<ExtendedAlertListItem> = this.alertsService;

  private executeBulkImport(): void {
    const clientId = this.params['clientId'];
    if (!isDefined(clientId) || clientId === '') {
      return;
    }

    const client = this.adminDataService['adminState'].selectedClient();
    const vendorId = client?.owner?.id;

    if (!isDefined(vendorId)) {
      return;
    }

    this.dialogRef = this.dialogService.open(VendorAlertPickerComponent, {
      header: this.translate.instant('ADMIN.ALERTS.IMPORT_VENDOR_ALERTS'),
      width: '75%',
      height: '80vh',
      contentStyle: {
        display: 'flex',
        flexDirection: 'column',
        padding: '0',
        height: '100%',
      },
      baseZIndex: 10000,
      data: { vendorId },
    });

    if (this.dialogRef) {
      this.dialogRef.onClose.subscribe(
        (selectedAlerts: ExtendedAlertListItem[] | undefined) => {
          if (isDefined(selectedAlerts) && selectedAlerts.length > 0) {
            this.importAlerts(selectedAlerts, clientId);
          }
        },
      );
    }
  }

  private importAlerts(
    alerts: ExtendedAlertListItem[],
    clientId: string,
  ): void {
    const importRequests = alerts.map((alert) => {
      const request: ExtendedAlertCreateRequest = {
        name: alert.name,
        priority: alert.priority,
        state: alert.state,
        filter: alert.filter,
        costCentre: alert.costCentre,
        ownerId: clientId,
        parentId: alert.id,
      };

      return this.entitiesService.createAlert(request).pipe(
        tap((createdAlert: AlertResponse) => {
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'alert',
            operation: 'create',
            entityId: createdAlert.id,
          });
        }),

        catchError((error) => {
          console.error(`Failed to import alert "${alert.name}":`, error);
          return of({ success: false, alertName: alert.name, error });
        }),
      );
    });

    forkJoin(importRequests)
      .pipe(
        finalize(() => {
          // Trigger grid refresh
          this.refreshTrigger.update((v) => v + 1);
        }),
      )
      .subscribe((results) => {
        const successCount = results.filter(
          (r) => !('success' in r) || r.success !== false,
        ).length;
        const failureCount = results.length - successCount;

        if (failureCount === 0) {
          this.messageService.add({
            severity: 'success',
            summary: 'Import Successful',
            detail: `Successfully imported ${successCount} alert${successCount === 1 ? '' : 's'}`,
          });
        } else if (successCount === 0) {
          this.messageService.add({
            severity: 'error',
            summary: 'Import Failed',
            detail: `Failed to import ${failureCount} alert${failureCount === 1 ? '' : 's'}`,
          });
        } else {
          this.messageService.add({
            severity: 'warn',
            summary: 'Partial Import',
            detail: `Imported ${successCount} alert${successCount === 1 ? '' : 's'}, ${failureCount} failed`,
          });
        }
      });
  }

  ownerId = '';

  private buildColumns(): GridColumn<ExtendedAlertListItem>[] {
    return [
      {
        field: 'name',
        header: this.translate.instant('ADMIN.ALERTS.COLUMNS.NAME'),
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
      },
      {
        field: 'costCentre',
        header: this.translate.instant('ADMIN.ALERTS.COLUMNS.COST_CENTRE'),
        valueGetter: (rowData: ExtendedAlertListItem) =>
          isDefined(rowData.costCentre?.name) ? rowData.costCentre?.name : '',
        filter: true,
        filterType: 'multiselect',
        filterMatchMode: 'in',
        filterConfig: {
          type: 'multiselect',
          options: [],
        },
      },
      {
        field: 'priority',
        header: this.translate.instant('ADMIN.ALERTS.COLUMNS.PRIORITY'),
        valueGetter: (rowData: ExtendedAlertListItem) =>
          isDefined(rowData.priority)
            ? this.priorityLabels[rowData.priority]
            : '',
        filter: true,
        filterType: 'multiselect',
        filterMatchMode: 'in',
        filterConfig: {
          type: 'multiselect',
          options: [
            {
              label: this.translate.instant('ADMIN.ALERTS.PRIORITIES.HIGH'),
              value: AlertListItem.PriorityEnum.High,
            },
            {
              label: this.translate.instant('ADMIN.ALERTS.PRIORITIES.MEDIUM'),
              value: AlertListItem.PriorityEnum.Medium,
            },
            {
              label: this.translate.instant('ADMIN.ALERTS.PRIORITIES.LOW'),
              value: AlertListItem.PriorityEnum.Low,
            },
          ],
        },
      },
      {
        field: 'state',
        header: this.translate.instant('ADMIN.ALERTS.COLUMNS.STATE'),
        valueGetter: (rowData: ExtendedAlertListItem) =>
          isDefined(rowData.state)
            ? this.translate.instant(
                `SHARED.COMMON.STATUS.${rowData.state.toUpperCase()}`,
              )
            : '',
        filter: true,
        filterType: 'multiselect',
        filterMatchMode: 'in',
        filterConfig: {
          type: 'multiselect',
          options: [
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.ACTIVE'),
              value: AlertListItem.StateEnum.Active,
            },
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.DELETED'),
              value: AlertListItem.StateEnum.Deleted,
            },
          ],
          defaultSelected: this.defaultStateValues,
        },
      },
      {
        field: 'modifiedDate',
        header: this.translate.instant('ADMIN.ALERTS.COLUMNS.MODIFIED'),
        filter: false,
        valueGetter: (rowData: ExtendedAlertListItem) =>
          isDefined(rowData.modifiedDate)
            ? this.measurementDateTimeService.formatDateTime(
                this.measurementDateTimeService.createDateAssumingUtc(
                  rowData.modifiedDate,
                ),
                DATE_FORMATS.DATE_TIME_SECONDS_YMD,
              )
            : '',
      },
    ];
  }

  getFilters(): Record<string, FilterCriteria> {
    return this.filterState();
  }

  clearFilters(): void {
    this.filterState.set({
      state: {
        value: this.defaultStateValues,
        operator: 'in',
      },
    });
  }

  initialize(params: Record<string, string>) {
    this.params = params;
    if (isDefined(this.params['clientId'])) {
      this.ownerId = String(this.params['clientId']);
      this.bulkImportIcon = 'pi pi-copy';
      this.bulkImportLabel = this.translate.instant(
        'ADMIN.ALERTS.IMPORT_VENDOR_ALERTS',
      );
      this.onBulkImport = () => this.executeBulkImport();
    } else {
      this.ownerId = isDefined(this.params['vendorId'])
        ? String(this.params['vendorId'])
        : '';
      this.bulkImportIcon = undefined;
      this.bulkImportLabel = undefined;
      this.onBulkImport = undefined;
    }
  }

  getTitle(): string {
    return this.translate.instant('ADMIN.ALERTS.TITLE');
  }

  getRequestParams(event?: TableLazyLoadEvent): DataGridParams {
    // Add sorting support
    let sortField = 'name:asc'; // Default

    if (isDefined(event?.sortField)) {
      const sortOrder = event.sortOrder === 1 ? 'asc' : 'desc';
      sortField = `${event.sortField}:${sortOrder}`;
    }

    return {
      owner: this.ownerId,
      offset: isDefined(event?.first) ? event.first : 0,
      recurse: false,
      limit: isDefined(event?.rows) ? event.rows : DEFAULT_PAGE_SIZE,
      sortField: sortField,
      filters: this.rqlFilter(),
    };
  }

  onFilterChange(field: string, value: FilterValue): void {
    const actualField = this.fieldTransformations[field] || field;
    const column = this.columns.find((col) => col.field === field);

    if (Array.isArray(value)) {
      const newFilters = this.gridBaseService.handleFilters(
        this.filterState(),
        actualField,
        value,
        undefined,
        column?.filterMatchMode,
      );

      this.filterState.set(newFilters);
      return;
    }

    // For non-array values, use the grid base service
    const newFilters = this.gridBaseService.handleFilters(
      this.filterState(),
      actualField,
      value,
      undefined,
      column?.filterMatchMode,
    );

    this.filterState.set(newFilters);
  }

  onAdd(): void {
    const ownerId = this.ownerId;

    this.openAlertCreationDialog(ownerId).subscribe((createdAlert) => {
      if (isDefined(createdAlert)) {
        // Refresh your alert list or take any other necessary actions
        // this.refreshAlerts();
      }
    });
  }

  openAlertCreationDialog(ownerId: string) {
    this.dialogRef = this.dialogService.open(AlertCreateWizardComponent, {
      header: this.translate.instant('SHARED.COMMON.WIZARD.TITLE', {
        entity: this.translate.instant('ADMIN.ENTITIES.ALERT'),
      }),
      contentStyle: { overflow: 'auto' },
      baseZIndex: 10000,
      data: { ownerId: ownerId },
      position: 'top',
      modal: true,
    });

    return (this.dialogRef as DynamicDialogRef).onClose;
  }
}
