import { inject, Injectable } from '@angular/core';
import { AdminStateService } from '../state/admin-state.service';
import { AdminTreeService } from './admin-tree.service';
import { BroadcastEventMessageService } from '../broadcast-event-messages.service';
import { DEFAULT_LIST_SIZE, DEFAULT_SYSTEM_ID } from '../../../../core/models';
import { isDefined, isNullOrUndefined } from '../../../../shared/utils';
import { ApiSchemaService } from '../../../../core/services/api-schema.service';

interface TreeRefreshMessage {
  entityType: 'distributor' | 'vendor' | 'client';
  operation: ClientRefreshOperation;
  distributorId?: string;
  vendorId?: string;
  entityId?: string;
  state?: string;
  includeDeleted?: boolean;
}

interface VendorFilterChangeMessage {
  distributorId: string;
  includeDeleted: boolean;
}

type ClientRefreshOperation = 'create' | 'update' | 'delete';
type RefreshStrategy = 'full-replace' | 'smart-update' | 'paginated-refresh';

/**
 * Service responsible for managing tree refresh operations for all entity types.
 * Centralizes the logic for keeping the admin tree in sync with entity changes.
 */
@Injectable({
  providedIn: 'root',
})
export class AdminTreeRefreshService {
  private readonly adminState = inject(AdminStateService);
  private readonly adminTreeService = inject(AdminTreeService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  private readonly apiSchemaService = inject(ApiSchemaService);

  /**
   * Initializes the service by setting up event listeners for tree refresh operations
   */
  initialize(): void {
    // Listen for tree refresh requirements
    this.broadcastService.on('tree-refresh-required').subscribe((message) => {
      this.handleTreeRefreshRequired(message);
    });

    // Listen for vendor filter changes from grid
    this.broadcastService.on('vendor-filter-changed').subscribe((message) => {
      this.handleVendorFilterChange(message);
    });
  }

  /**
   * Handles refreshing vendor data in the tree based on state changes
   * @param distributorId - The ID of the parent distributor
   * @param includeDeleted - Whether to include deleted vendors (for filtering)
   */
  async refreshVendorData(
    distributorId: string,
    includeDeleted = false,
  ): Promise<void> {
    try {
      // Create filter based on whether to include deleted items
      const filter = includeDeleted ? undefined : 'state!=deleted';

      const vendors = await this.adminTreeService.listDistributorVendors(
        distributorId,
        filter,
      );

      this.adminState.setDistributorVendors(distributorId, vendors);
    } catch (error) {
      console.error('Error refreshing vendor data:', error);
      throw error;
    }
  }

  /**
   * Handles refreshing distributor data under super-admin
   */
  refreshDistributorData(_message: TreeRefreshMessage): void {
    const usesModernSchema = this.apiSchemaService.usesModernSchema();
    const superAdminExpandedNodes =
      this.adminState.expandedNodes()['super-admin'] ?? new Set();

    // If super admin is already expanded OR using modern schema, we must refresh to avoid stale list
    if (usesModernSchema || superAdminExpandedNodes.has('super-admin-root')) {
      this.adminState.setInitialLoading(true);
      this.adminTreeService
        .listDistributors(DEFAULT_SYSTEM_ID)
        .then((distributors) => {
          this.adminState.setDistributors(distributors);
        })
        .catch((error) => {
          console.error('Error refreshing distributor list:', error);
        })
        .finally(() => {
          this.adminState.setInitialLoading(false);
        });
    }
  }

  /**
   * Handles refreshing client data for a specific vendor
   * @param vendorId - The ID of the vendor whose clients should be refreshed
   * @param distributorId - The ID of the parent distributor
   * @param operation - The operation that triggered the refresh (affects strategy)
   */
  async refreshClientData(
    vendorId: string,
    distributorId: string,
    operation: ClientRefreshOperation = 'update',
  ): Promise<void> {
    try {
      // Check if vendor is expanded using distributor-scoped expansion state
      const isVendorExpanded = this.adminState.isDistributorNodeExpanded(
        distributorId,
        vendorId,
      );

      if (!isVendorExpanded) {
        return;
      }

      // Get current client state to determine strategy
      // Note: AdminStateService methods may not exist yet, so we use optional chaining
      const currentClients = this.adminState.getDistributorVendorClients?.(
        distributorId,
        vendorId,
      );
      // Future enhancement: Add pagination info when AdminStateService has these methods
      // const currentPaginationInfo = this.adminState.getDistributorVendorClientsPaginationInfo?.(distributorId, vendorId);

      // Determine refresh strategy based on operation and current state
      const strategy = this.determineClientRefreshStrategy(
        operation,
        currentClients,
        null,
      );

      switch (strategy) {
        case 'full-replace':
          await this.fullClientReplace(vendorId, distributorId);
          break;

        case 'smart-update':
          await this.smartClientUpdate(vendorId, distributorId, operation);
          break;

        case 'paginated-refresh':
          await this.paginatedClientRefresh(vendorId, distributorId, null);
          break;

        default:
          console.warn('Unknown refresh strategy:', strategy);
          // Fall back to full replace
          await this.fullClientReplace(vendorId, distributorId);
      }
    } catch (error) {
      console.error('Error refreshing client data:', error);
      throw error;
    }
  }

  /**
   * Determines the best refresh strategy based on current state and operation
   */
  private determineClientRefreshStrategy(
    operation: ClientRefreshOperation,
    currentClients: unknown,
    _paginationInfo: unknown,
  ): RefreshStrategy {
    // If no clients loaded yet, do a full replace
    if (
      currentClients === undefined ||
      currentClients === null ||
      (Array.isArray(currentClients) && currentClients.length === 0)
    ) {
      return 'full-replace';
    }

    // Different strategies based on operation type
    switch (operation) {
      case 'delete':
        // For deletions, always do full replace to ensure deleted items are removed
        return 'full-replace';

      case 'create':
        // For creates, we could use smart update but full replace is safer for now
        // In the future, this could be 'smart-update' to append new items
        return 'full-replace';

      case 'update':
        // For updates, smart update could work to just refresh existing items
        // But for now, full replace ensures we get the latest state
        return 'smart-update';

      default:
        return 'full-replace';
    }
  }

  /**
   * Full replace strategy - replaces all client data with fresh first page
   */
  private async fullClientReplace(
    vendorId: string,
    distributorId: string,
  ): Promise<void> {
    const result = await this.adminTreeService.listVendorClients(vendorId);

    this.adminState.addDistributorVendorClients(
      distributorId,
      vendorId,
      result.clients,
      {
        offset: 0,
        limit: DEFAULT_LIST_SIZE,
        total: result.total,
        hasMore: result.hasMore,
      },
      false, // Replace existing clients
    );
  }

  /**
   * Smart update strategy - handles specific operations without losing pagination
   */
  private async smartClientUpdate(
    vendorId: string,
    distributorId: string,
    _operation: ClientRefreshOperation,
  ): Promise<void> {
    // For now, fall back to full replace
    // This can be enhanced later with more sophisticated logic
    await this.fullClientReplace(vendorId, distributorId);
  }

  /**
   * Paginated refresh strategy - refreshes all currently loaded pages
   */
  private async paginatedClientRefresh(
    vendorId: string,
    distributorId: string,
    _currentPaginationInfo?: unknown,
  ): Promise<void> {
    // For now, fall back to full replace
    // This can be enhanced later when pagination info is available
    await this.fullClientReplace(vendorId, distributorId);
  }

  /**
   * Handles tree refresh requirements after entity operations
   */
  private handleTreeRefreshRequired(message: unknown): void {
    // Basic shape guard
    if (
      !isDefined(message) ||
      message === null ||
      typeof message !== 'object' ||
      !('entityType' in message) ||
      !('operation' in message)
    ) {
      return;
    }

    const m = message as TreeRefreshMessage;

    switch (m.entityType) {
      case 'vendor':
        this.handleVendorRefresh(m);
        break;

      case 'distributor':
        this.handleDistributorRefresh(m);
        break;

      case 'client':
        this.handleClientRefresh(m);
        break;

      default:
        console.warn('Unhandled entity type for tree refresh:', m.entityType);
    }
  }

  /**
   * Handles vendor-specific refresh logic
   */
  private handleVendorRefresh(message: TreeRefreshMessage): void {
    // Prefer distributorId from message if provided
    const distributorId =
      message.distributorId ?? this.adminState.vendorDistributor()?.id;

    if (isNullOrUndefined(distributorId) || distributorId === '') {
      console.warn('Vendor refresh requested but no distributorId available.');
      return;
    }

    // Refresh the distributor's vendor list in state even if not expanded
    if (distributorId) {
      this.adminTreeService
        .listDistributorVendors(distributorId)
        .then((vendors) => {
          this.adminState.setDistributorVendors(distributorId, vendors);
        })
        .catch((error: unknown) => {
          console.error('Error handling vendor refresh:', error);
        });
    }

    // If distributor is not expanded, it will load fresh vendors when next expanded
    // but the state update above ensures any existing UI is current.
    if (!this.adminState.isDistributorExpanded(distributorId)) {
      return;
    }

    // For updates, check if we need to include deleted vendors based on current filter state
    const includeDeleted = message.includeDeleted ?? false;

    this.refreshVendorData(distributorId, includeDeleted).catch(
      (error: unknown) => {
        console.error('Error handling vendor refresh:', error);
      },
    );
  }

  /**
   * Handles distributor-specific refresh logic
   */
  private handleDistributorRefresh(_message: TreeRefreshMessage): void {
    this.refreshDistributorData(_message); // Pass message to the updated refreshDistributorData
  }

  /**
   * Handles client-specific refresh logic
   */
  private handleClientRefresh(message: TreeRefreshMessage): void {
    const context = this.extractClientContext(message);
    const { vendorId, distributorId } = context;

    if (
      isNullOrUndefined(vendorId) ||
      vendorId === '' ||
      isNullOrUndefined(distributorId) ||
      distributorId === ''
    ) {
      console.warn(
        'Client refresh requested but no vendorId or distributorId available.',
        context,
      );
      return;
    }

    if (isDefined(vendorId) && isDefined(distributorId)) {
      const isExpanded = this.adminState.isDistributorNodeExpanded(
        distributorId,
        vendorId,
      );
      if (isExpanded) {
        this.refreshClientData(vendorId, distributorId).catch((error) => {
          console.error('Error refreshing client data:', error);
        });
      } else {
        // If not expanded, mark node as NOT loaded in state.
        // This forces AdminDataService to fetch fresh data when it is next expanded.
        this.adminState.removeDistributorLoadedVendor(distributorId, vendorId);
      }
    }
  }

  /**
   * Extracts vendor and distributor context for client operations
   */
  private extractClientContext(message: TreeRefreshMessage): {
    vendorId: string | undefined;
    distributorId: string | undefined;
  } {
    // 1. Try values directly from message (best case)
    let vendorId = message.vendorId;
    let distributorId = message.distributorId;

    // 2. Try to recover vendorId from current state if missing
    if (isNullOrUndefined(vendorId) || vendorId === '') {
      vendorId = this.adminState.clientVendor()?.id;
    }

    // 3. Try to recover distributorId from current state if missing
    if (isNullOrUndefined(distributorId) || distributorId === '') {
      distributorId = this.adminState.vendorDistributor()?.id;
    }

    // 4. Fallback: if we have vendorId but no distributorId, try to get distributorId from vendor object
    if (
      isDefined(vendorId) &&
      vendorId !== '' &&
      (isNullOrUndefined(distributorId) || distributorId === '')
    ) {
      const vendor = this.adminState.clientVendor();
      if (vendor?.id === vendorId) {
        distributorId = vendor.owner?.id;
      }
    }

    return { vendorId, distributorId };
  }

  /**
   * Handles vendor filter changes from the grid
   */
  private handleVendorFilterChange(message: unknown): void {
    if (
      !isDefined(message) ||
      message === null ||
      typeof message !== 'object' ||
      !('distributorId' in message) ||
      !('includeDeleted' in message)
    ) {
      return;
    }

    const m = message as VendorFilterChangeMessage;

    // Refresh vendor data with the new filter setting
    this.refreshVendorData(m.distributorId, m.includeDeleted).catch(
      (error: unknown) => {
        console.error('Error handling vendor filter change:', error);
      },
    );
  }

  /**
   * Manually triggers a vendor refresh for a specific distributor
   * @param distributorId - The distributor ID
   * @param includeDeleted - Whether to include deleted vendors
   */
  async triggerVendorRefresh(
    distributorId: string,
    includeDeleted = false,
  ): Promise<void> {
    return this.refreshVendorData(distributorId, includeDeleted);
  }

  /**
   * Manually triggers a client refresh for a specific vendor
   * @param vendorId - The vendor ID
   * @param distributorId - The distributor ID
   * @param operation - The type of operation that triggered this refresh
   */
  async triggerClientRefresh(
    vendorId: string,
    distributorId: string,
    operation: ClientRefreshOperation = 'update',
  ): Promise<void> {
    return this.refreshClientData(vendorId, distributorId, operation);
  }
}
