import { CommonModule } from '@angular/common';
import {
  Component,
  DestroyRef,
  OnInit,
  TemplateRef,
  effect,
  inject,
  signal,
  viewChild,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { ReactiveFormsModule } from '@angular/forms';
import { finalize } from 'rxjs';

import { ButtonModule } from 'primeng/button';
import { DynamicDialogRef, DynamicDialogConfig } from 'primeng/dynamicdialog';

import {
  EntitiesService,
  EventActorFilter,
  ExportTaskCreateRequest,
  ExportTaskResponse,
  ClientListItem,
} from '../../../../../api';
import { WizardComponent } from '../../../../../shared/components/wizard/wizard.component';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { BroadcastEventMessageService } from '../../../services/broadcast-event-messages.service';
import { ExportTaskDetailsSectionComponent } from '../export-task-details-section/export-task-details-section.component';
import { ExportTaskSettingsSectionComponent } from '../export-task-settings-section/export-task-settings-section.component';
import { Step } from '../../../../../shared/models';
import { TranslatePipe, TranslateService } from '@ngx-translate/core';
import { LanguageService } from '../../../../../core/services/language.service';

@Component({
  selector: 'app-export-task-create-wizard',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    WizardComponent,
    ButtonModule,
    ExportTaskDetailsSectionComponent,
    ExportTaskSettingsSectionComponent,
    TranslatePipe,
  ],
  templateUrl: './export-task-create-wizard.component.html',
  styleUrl: './export-task-create-wizard.component.scss',
})
export class ExportTaskCreateWizardComponent implements OnInit {
  exportTaskDetailsStep = viewChild<TemplateRef<{ $implicit: Step }>>(
    'exportTaskDetailsStep',
  );
  exportTaskSettingsStep = viewChild<TemplateRef<{ $implicit: Step }>>(
    'exportTaskSettingsStep',
  );
  confirmationTemplate = viewChild<TemplateRef<{ $implicit: Step }>>(
    'confirmationTemplate',
  );

  exportTaskDetailsForm = viewChild<ExportTaskDetailsSectionComponent>(
    'exportTaskDetailsForm',
  );
  exportTaskSettingsForm = viewChild<ExportTaskSettingsSectionComponent>(
    'exportTaskSettingsForm',
  );

  private readonly entitiesService = inject(EntitiesService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  protected readonly destroyRef = inject(DestroyRef);
  private readonly dialogRef = inject(DynamicDialogRef);
  private readonly dialogConfig = inject(DynamicDialogConfig);
  private readonly languageService = inject(LanguageService);
  private readonly translate = inject(TranslateService);

  newExportTask = signal<Partial<ExportTaskCreateRequest>>({});
  steps: Step[] = [];
  ownerId: string | null = null;
  isSubmitting = signal<boolean>(false);

  constructor() {
    effect(() => {
      const exportTaskDetailsStep = this.exportTaskDetailsStep();
      const exportTaskSettingsStep = this.exportTaskSettingsStep();
      const confirmationTemplate = this.confirmationTemplate();

      if (
        isNullOrUndefined(exportTaskDetailsStep) ||
        isNullOrUndefined(exportTaskSettingsStep) ||
        isNullOrUndefined(confirmationTemplate)
      ) {
        return;
      }

      this.steps = [
        {
          value: 1,
          header: 'Export Task Details',
          content: exportTaskDetailsStep,
          complete: false,
          validate: () => this.exportTaskDetailsForm()?.validate() ?? false,
        },
        {
          value: 2,
          header: 'Export Task Settings',
          content: exportTaskSettingsStep,
          complete: false,
          validate: () => this.exportTaskSettingsForm()?.validate() ?? false,
        },
        {
          value: 3,
          header: 'Confirmation',
          content: confirmationTemplate,
          complete: true,
        },
      ];
    });
  }

  ngOnInit(): void {
    if (isDefined(this.dialogConfig.data)) {
      this.ownerId = this.dialogConfig.data.ownerId ?? null;
      this.newExportTask.update((current) => ({
        ...current,
        ownerId: this.ownerId ?? '',
      }));
    }
  }

  onDetailsFormValidityChange(isValid: boolean): void {
    this.steps[0].disableNext = !isValid;
  }

  onSettingsFormValidityChange(isValid: boolean): void {
    this.steps[1].disableNext = !isValid;
  }

  onFormValueChange(formData: Record<string, unknown>): void {
    this.newExportTask.update((current) => {
      const updated = { ...current };
      Object.keys(formData).forEach((key) => {
        if (key !== 'ownerId') {
          updated[key] = formData[key];
        }
      });
      if (isNullOrUndefined(updated['ownerId'])) {
        updated['ownerId'] = this.ownerId ?? '';
      }
      return updated;
    });
  }

  onWizardComplete(): void {
    const formData = this.newExportTask() as Record<string, unknown>;
    const isFirehose = formData['deliveryMethod'] === 'firehose';

    const request: ExportTaskCreateRequest = {
      ownerId: this.ownerId ?? '',
      name: formData['name'] as string,
      deliveryMethod: formData[
        'deliveryMethod'
      ] as ExportTaskCreateRequest.DeliveryMethodEnum,
      documentTypes: formData['documentTypes'] as string[],
      documentVersion: formData[
        'documentVersion'
      ] as ExportTaskCreateRequest.DocumentVersionEnum,
    };

    if (isFirehose) {
      request.client = { id: this.ownerId ?? '' };
    } else if (
      isDefined(formData['client']) &&
      typeof formData['client'] === 'object'
    ) {
      const selected = formData['client'] as { id?: string; name?: string };
      request.client = { id: selected.id ?? '', name: selected.name };
    }

    if ('assets' in formData) {
      if (isFirehose) {
        const clients = (formData['assets'] as ClientListItem[]) ?? [];
        request.assets = clients.map((c) => ({
          actorType: 'client',
          actorTypeId: c.id,
          actorTypeName: c.name,
          actorSelectionType: 'specific',
          actorId: c.id,
          actorName: c.name,
          text: c.name,
        }));
      } else {
        request.assets = formData['assets'] as EventActorFilter[];
      }
    }

    const settingsFields = [
      'endpointType',
      'endpoint',
      'prefix',
      'encoding',
      'parameters',
      'accessKey',
    ];
    const settingsData: Record<string, unknown> = {};
    settingsFields.forEach((field) => {
      if (field in formData) {
        settingsData[field] = formData[field];
      }
    });
    if (Object.keys(settingsData).length > 0) {
      request.settings = settingsData as ExportTaskCreateRequest['settings'];
    }

    this.isSubmitting.set(true);
    this.entitiesService
      .createExportTask(request)
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        finalize(() => this.isSubmitting.set(false)),
      )
      .subscribe({
        next: (response: ExportTaskResponse) => {
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'exporttask',
            operation: 'create',
            entityId: response.id,
          });
          this.dialogRef.close(response);
        },
        error: (error: Error) => {
          console.error('Error creating export task:', error);
        },
      });
  }

  onWizardCancel(): void {
    this.newExportTask.set({});
    this.dialogRef.close();
  }
}
