import { Injectable, computed, inject, signal } from '@angular/core';

import { TableLazyLoadEvent } from 'primeng/table';

import {
  GridConfiguration,
  GridDataService,
  DataGridParams,
  GridColumn,
  FilterCriteria,
  FilterValue,
  DATE_FORMATS,
} from '../../../shared/models';
import { UtilityService } from '../../../core/services/utility.service';
import { GridBaseService } from '../../../shared/services/grid-base.service';
import {
  enumToSelectOptionValues,
  isDefined,
  isString,
} from '../../../shared/utils';
import { ExportTasksDataAdapter } from '../services/adapters';
import { ExportTaskListItem } from '../../../api';
import { DEFAULT_PAGE_SIZE } from '../../../core/models';
import { DynamicDialogRef, DialogService } from 'primeng/dynamicdialog';
import { ExportTaskCreateWizardComponent } from '../components/export-tasks/export-task-create-wizard/export-task-create-wizard.component';
import { MeasurementDateTimeService } from '../../../shared/services/measurement-units/measurement-date-time.service';

@Injectable({
  providedIn: 'root',
})
export class ExportTasksGridConfig implements GridConfiguration<ExportTaskListItem> {
  private readonly exportTasksService = inject(ExportTasksDataAdapter);
  private readonly utilityService = inject(UtilityService);
  private readonly gridBaseService = inject(GridBaseService);
  private dialogRef: DynamicDialogRef | null = null;
  private readonly dialogService = inject(DialogService);
  private readonly measurementDateTimeService = inject(
    MeasurementDateTimeService,
  );

  private readonly defaultStateValues = [
    ExportTaskListItem.StateEnum.Active,
    ExportTaskListItem.StateEnum.Suspended,
  ];
  private readonly defaultDeliveryMethodValues = [
    ExportTaskListItem.DeliveryMethodEnum.Http,
    ExportTaskListItem.DeliveryMethodEnum.Stream,
    ExportTaskListItem.DeliveryMethodEnum.Firehose,
  ];
  private readonly filterState = signal<Record<string, FilterCriteria>>({
    state: {
      value: this.defaultStateValues,
      operator: 'in',
    },
    deliveryMethod: {
      value: this.defaultDeliveryMethodValues,
      operator: 'in',
    },
  });
  private params: Record<string, string> = { ownerId: '' };
  private ownerId = '';

  private readonly rqlFilter = computed(() =>
    this.utilityService.constructRqlFilter(this.filterState()),
  );

  private readonly stateLabels: Record<ExportTaskListItem.StateEnum, string> = {
    active: 'Active',
    suspended: 'Suspended',
    deleted: 'Deleted',
  };

  entityType = 'export-tasks';
  columns: GridColumn<ExportTaskListItem>[] = [
    {
      field: 'name',
      header: 'Name',
      filter: true,
      filterType: 'text',
      filterMatchMode: 'contains',
    },
    {
      field: 'deliveryMethod',
      header: 'Mode',
      valueGetter: (rowData: ExportTaskListItem) =>
        isDefined(rowData.deliveryMethod)
          ? this.utilityService.toTitleCase(rowData.deliveryMethod)
          : '',
      filter: true,
      filterType: 'multiselect',
      filterMatchMode: 'in',
      filterConfig: {
        type: 'multiselect',
        options: enumToSelectOptionValues(
          ExportTaskListItem.DeliveryMethodEnum,
        ),
        defaultSelected: this.defaultDeliveryMethodValues,
      },
      transform: 'capitalize',
    },
    {
      field: 'client',
      header: 'Client',
      valueGetter: (rowData: ExportTaskListItem) =>
        isDefined(rowData.client) && isString(rowData.client.name)
          ? rowData.client.name
          : '',
      filter: true,
      filterType: 'text',
      filterMatchMode: 'contains',
    },
    {
      field: 'state',
      header: 'State',
      valueGetter: (rowData: ExportTaskListItem) =>
        isDefined(rowData.state) ? this.stateLabels[rowData.state] : '',
      filter: true,
      filterType: 'multiselect',
      filterMatchMode: 'in',
      filterConfig: {
        type: 'multiselect',
        options: [
          { label: 'Active', value: ExportTaskListItem.StateEnum.Active },
          { label: 'Suspended', value: ExportTaskListItem.StateEnum.Suspended },
          { label: 'Deleted', value: ExportTaskListItem.StateEnum.Deleted },
        ],
        defaultSelected: this.defaultStateValues,
      },
      transform: 'capitalize',
    },
    {
      field: 'modifiedDate',
      header: 'Modified',
      filter: false,
      valueGetter: (rowData: ExportTaskListItem) =>
        isDefined(rowData.modifiedDate)
          ? this.measurementDateTimeService.formatDateTime(
              this.measurementDateTimeService.createDateAssumingUtc(
                rowData.modifiedDate,
              ),
              DATE_FORMATS.DATE_TIME_SECONDS_YMD,
            )
          : '',
    },
  ];

  dataService: GridDataService<ExportTaskListItem> = this.exportTasksService;

  getFilters(): Record<string, FilterCriteria> {
    return this.filterState();
  }

  clearFilters(): void {
    this.filterState.set({
      state: {
        value: this.defaultStateValues,
        operator: 'in',
      },
      deliveryMethod: {
        value: this.defaultDeliveryMethodValues,
        operator: 'in',
      },
    });
  }

  initialize(params: Record<string, string>): void {
    this.params = params;
    if (isDefined(this.params['vendorId'])) {
      this.ownerId = String(this.params['vendorId']);
    } else if (isDefined(this.params['distributorId'])) {
      this.ownerId = String(this.params['distributorId']);
    }
  }

  getTitle(): string {
    return 'Export Tasks';
  }

  getRequestParams(event?: TableLazyLoadEvent): DataGridParams {
    // Add sorting support
    let sortField = 'name:asc'; // Default

    if (isDefined(event?.sortField)) {
      const sortOrder = event.sortOrder === 1 ? 'asc' : 'desc';
      sortField = `${event.sortField}:${sortOrder}`;
    }

    return {
      owner: this.ownerId,
      offset: isDefined(event?.first) ? event.first : 0,
      limit: isDefined(event?.rows) ? event.rows : DEFAULT_PAGE_SIZE,
      sortField: sortField,
      filters: this.rqlFilter(),
    };
  }

  onFilterChange(field: string, value: FilterValue): void {
    const column = this.columns.find((col) => col.field === field);

    if (Array.isArray(value)) {
      const newFilters = this.gridBaseService.handleFilters(
        this.filterState(),
        field,
        value,
        undefined,
        column?.filterMatchMode,
      );

      this.filterState.set(newFilters);
      return;
    }

    // For non-array values, use the grid base service
    const newFilters = this.gridBaseService.handleFilters(
      this.filterState(),
      field,
      value,
      undefined,
      column?.filterMatchMode,
    );

    this.filterState.set(newFilters);
  }

  onAdd(): void {
    this.openExportTaskCreationDialog(this.ownerId).subscribe();
  }

  openExportTaskCreationDialog(ownerId: string) {
    this.dialogRef = this.dialogService.open(ExportTaskCreateWizardComponent, {
      header: 'Export Task Wizard',
      contentStyle: { overflow: 'auto' },
      baseZIndex: 10000,
      data: { ownerId: ownerId },
      position: 'top',
      modal: true,
    });

    return (this.dialogRef as DynamicDialogRef).onClose;
  }
}
