import { Injectable } from '@angular/core';
import { Observable, catchError, from, map, switchMap, throwError } from 'rxjs';
import { TreeTableColumn } from '../models';

const XLSX_MIME_TYPE =
  'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet';

/**
 * Generates a real `.xlsx` workbook for grid exports.
 *
 * Exists because CSV cannot round-trip long numeric identifiers (IMEIs, SIM
 * serials) through Excel: on open Excel converts them to scientific notation
 * (`3,50317E+14`) and drops digits past its 15-digit float precision, and
 * modern Excel builds no longer honour the classic in-band `="..."` /
 * tab-prefix text hints. In an `.xlsx`, string cells are unambiguously text,
 * so the full identifier survives a plain double-click open.
 *
 * Mirrors {@link CsvExportService}'s API and column semantics: honours
 * `exportable !== false` and resolves each cell through the column's
 * `valueGetter` when present. All cells are written as text, matching the CSV
 * export's output.
 */
@Injectable({ providedIn: 'root' })
export class XlsxExportService {
  /**
   * Build and download `filename` containing one worksheet with a header row
   * followed by one row per item. Returns an `Observable<void>` that completes
   * once the download has been triggered, so callers can drive a loading
   * indicator. ExcelJS is imported lazily to keep it out of the main bundle.
   */
  export<T>(
    columns: TreeTableColumn<T>[],
    rows: T[],
    filename: string,
    sheetName = 'Export',
  ): Observable<void> {
    const exportCols = columns.filter((col) => col.exportable !== false);

    return from(import('exceljs')).pipe(
      switchMap((excelModule) => {
        // The exceljs browser build is a UMD/CommonJS bundle, so a dynamic
        // import exposes the library under `.default` — its named members
        // (Workbook, …) are NOT hoisted onto the namespace, so
        // `excelModule.Workbook` is undefined. Unwrap `.default`, falling back
        // to the namespace itself in case a future build ships real ESM.
        const ExcelJS = excelModule.default ?? excelModule;
        const workbook = new ExcelJS.Workbook();
        const worksheet = workbook.addWorksheet(sheetName);

        worksheet.columns = exportCols.map((col) => ({
          header: col.header,
          // Reasonable default width; long identifiers stay readable.
          width: Math.max(col.header.length + 2, 15),
        }));
        worksheet.getRow(1).font = { bold: true };

        for (const row of rows) {
          worksheet.addRow(
            exportCols.map((col) => String(this.resolveValue(col, row) ?? '')),
          );
        }

        return from(workbook.xlsx.writeBuffer());
      }),
      map((buffer) => {
        this.triggerDownload(buffer, filename);
      }),
      catchError((error: unknown) => {
        // The grid/tree-table containers swallow export errors to keep the UI
        // stable; log here so failures are diagnosable instead of silent.
        console.error(`XlsxExportService: failed to export "${filename}"`, error);
        return throwError(() => error);
      }),
    );
  }

  private triggerDownload(buffer: ArrayBuffer, filename: string): void {
    const blob = new Blob([buffer], { type: XLSX_MIME_TYPE });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    a.click();
    URL.revokeObjectURL(url);
  }

  private resolveValue<T>(col: TreeTableColumn<T>, row: T): string | number {
    if (col.valueGetter) return col.valueGetter(row);

    const field = col.field as string;
    if (field.includes('.')) {
      return this.resolvePath(row as Record<string, unknown>, field);
    }
    return String((row as Record<string, unknown>)[field] ?? '');
  }

  private resolvePath(obj: Record<string, unknown>, path: string): string {
    const value = path.split('.').reduce<unknown>((acc, key) => {
      return acc != null && typeof acc === 'object'
        ? (acc as Record<string, unknown>)[key]
        : undefined;
    }, obj);
    return String(value ?? '');
  }
}
