import { computed, inject, Injectable } from '@angular/core';

import {
  DATE_FORMATS,
  DataGridParams,
  TreeTableColumn,
  TreeTableConfiguration,
} from '../../../shared/models';

import { DEFAULT_LIST_SIZE, DEFAULT_SYSTEM_ID } from '../../../core/models';
import { DeviceTypeListItem } from '../../../api/model/deviceTypeListItem';
import { DeviceTypesDataAdapter } from '../services/adapters/device-types.adapter.service';
import { MeasurementDateTimeService } from '../../../shared/services/measurement-units/measurement-date-time.service';
import { TableLazyLoadEvent } from 'primeng/table';
import { isDefined } from '../../../shared/utils';
import { DynamicDialogRef, DialogService } from 'primeng/dynamicdialog';
import { DeviceTypesCreateWizardComponent } from '../components/device-types/device-types-create-wizard/device-types-create-wizard.component';
import { TranslateService } from '@ngx-translate/core';
import { LanguageService } from '../../../core/services/language.service';

@Injectable({ providedIn: 'root' })
export class DeviceTypesGridConfig implements TreeTableConfiguration<DeviceTypeListItem> {
  private readonly deviceTypesService = inject(DeviceTypesDataAdapter);
  private readonly measurementDateTimeService = inject(
    MeasurementDateTimeService,
  );
  private dialogRef: DynamicDialogRef | null = null;
  private readonly dialogService = inject(DialogService);
  private readonly translate = inject(TranslateService);
  private readonly languageService = inject(LanguageService);

  private params: Record<string, string> = { clientId: '' };

  dataService = this.deviceTypesService;

  entityType = 'device-types';
  columns: TreeTableColumn<DeviceTypeListItem>[] = this.buildColumns();
  readonly columnsSignal = computed(() => {
    this.languageService.currentLanguage();
    return this.buildColumns();
  });

  private buildColumns(): TreeTableColumn<DeviceTypeListItem>[] {
    return [
      {
        field: 'name',
        header: this.translate.instant('ADMIN.DEVICE_TYPES.COLUMNS.NAME'),
        filterType: 'text',
      },
      {
        field: 'shortName',
        header: this.translate.instant('ADMIN.DEVICE_TYPES.COLUMNS.SHORT_NAME'),
        filterType: 'text',
      },
      {
        field: 'tag',
        header: this.translate.instant('ADMIN.DEVICE_TYPES.COLUMNS.TAG'),
        filterType: 'text',
      },
      {
        field: 'state',
        header: this.translate.instant('ADMIN.DEVICE_TYPES.COLUMNS.STATUS'),
        filterType: 'multiselect',
      },
      {
        field: 'modifiedDate',
        header: this.translate.instant('ADMIN.DEVICE_TYPES.COLUMNS.MODIFIED'),
        valueGetter: (rowData: DeviceTypeListItem) =>
          isDefined(rowData.modifiedDate)
            ? this.measurementDateTimeService.formatDateTime(
                this.measurementDateTimeService.createDateAssumingUtc(
                  rowData.modifiedDate,
                ),
                DATE_FORMATS.DATE_TIME_SECONDS_YMD,
              )
            : '',
      },
    ];
  }

  defaultVisibleColumns = ['name', 'shortName', 'state', 'modifiedDate'];

  getTitle(): string {
    return this.translate.instant('ADMIN.DEVICE_TYPES.TITLE');
  }

  initialize(params: Record<string, string>): void {
    this.params = params;
  }

  getRequestParams(event?: TableLazyLoadEvent): DataGridParams {
    let sortField = 'name:asc';

    if (isDefined(event?.sortField) && event.sortField !== '') {
      const sortOrder = event.sortOrder === 1 ? 'asc' : 'desc';
      sortField = `${event.sortField}:${sortOrder}`;
    }

    return {
      owner: DEFAULT_SYSTEM_ID,
      offset: isDefined(event?.first) ? event.first : 0,
      recurse: false,
      limit: DEFAULT_LIST_SIZE,
      sortField,
      filters: '',
    };
  }

  onAdd(): void {
    const ownerId = DEFAULT_SYSTEM_ID;
    this.openDeviceTypeCreationDialog(ownerId).subscribe();
  }

  openDeviceTypeCreationDialog(ownerId: string) {
    this.dialogRef = this.dialogService.open(DeviceTypesCreateWizardComponent, {
      header: this.translate.instant('SHARED.COMMON.WIZARD.TITLE', {
        entity: this.translate.instant('ADMIN.ENTITIES.DEVICE_TYPE'),
      }),
      contentStyle: { overflow: 'auto' },
      baseZIndex: 10000,
      data: { ownerId: ownerId },
      position: 'top',
      modal: true,
    });

    return (this.dialogRef as DynamicDialogRef).onClose;
  }
}
