import {
  DestroyRef,
  Injectable,
  computed,
  inject,
  signal,
} from '@angular/core';

import { TableLazyLoadEvent } from 'primeng/table';
import { catchError, combineLatest, EMPTY } from 'rxjs';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

import {
  GridConfiguration,
  GridDataService,
  DataGridParams,
  GridColumn,
  FilterCriteria,
  FilterValue,
  DATE_FORMATS,
} from '../../../shared/models';
import { UtilityService } from '../../../core/services/utility.service';
import { GridBaseService } from '../../../shared/services/grid-base.service';
import { isDefined } from '../../../shared/utils';
import { GeofencesDataAdapter } from '../services/adapters';
import { EntitiesService, ZoneListItem } from '../../../api';
import { DEFAULT_PAGE_SIZE } from '../../../core/models';
import { DynamicDialogRef, DialogService } from 'primeng/dynamicdialog';
import { GeofenceCreateWizardComponent } from '../components/geofences/geofence-create-wizard/geofence-create-wizard.component';
import { MeasurementDateTimeService } from '../../../shared/services/measurement-units/measurement-date-time.service';
import { TranslateService } from '@ngx-translate/core';
import { LanguageService } from '../../../core/services/language.service';

@Injectable({
  providedIn: 'root',
})
export class GeofencesGridConfig implements GridConfiguration<ZoneListItem> {
  entityType = 'geofences';

  private readonly geofencesService = inject(GeofencesDataAdapter);
  private readonly utilityService = inject(UtilityService);
  private readonly gridBaseService = inject(GridBaseService);
  private readonly entitiesService = inject(EntitiesService);
  private dialogRef: DynamicDialogRef | null = null;
  private readonly dialogService = inject(DialogService);
  private readonly measurementDateTimeService = inject(
    MeasurementDateTimeService,
  );
  private readonly translate = inject(TranslateService);
  private readonly languageService = inject(LanguageService);

  private readonly defaultStateValues = ['active', 'inactive'];
  private readonly filterState = signal<Record<string, FilterCriteria>>({
    state: {
      value: this.defaultStateValues,
      operator: 'in',
    },
  });
  private params: Record<string, string> = { clientId: '' };
  private readonly destroyRef = inject(DestroyRef);

  private readonly rqlFilter = computed(() =>
    this.utilityService.constructRqlFilter(this.filterState()),
  );
  private readonly fieldTransformations: Record<string, string> = {
    costCentre: 'costCentre.id',
    groups: 'groups.id',
  };
  private readonly zoneTypeTranslationKeys: Record<string, string> = {
    location: 'ADMIN.ZONES.DETAILS.TYPES.LOCATION',
    keepin: 'ADMIN.ZONES.DETAILS.TYPES.KEEP_IN',
    nogo: 'ADMIN.ZONES.DETAILS.TYPES.NO_GO',
    route: 'ADMIN.ZONES.DETAILS.TYPES.ROUTE',
  };

  columns: GridColumn<ZoneListItem>[] = this.buildColumns();
  readonly columnsSignal = computed(() => {
    this.languageService.currentLanguage();
    return this.buildColumns();
  });

  defaultVisibleColumns = ['name', 'zoneType', 'costCentre', 'group', 'state'];

  dataService: GridDataService<ZoneListItem> = this.geofencesService;

  private buildColumns(): GridColumn<ZoneListItem>[] {
    return [
      {
        field: 'name',
        header: this.translate.instant('ADMIN.ZONES.COLUMNS.NAME'),
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
      },
      {
        field: 'zoneType',
        header: this.translate.instant('ADMIN.ZONES.COLUMNS.TYPE'),
        sortable: true,
        filterType: 'multiselect',
        filter: true,
        filterMatchMode: 'in',
        valueGetter: (rowData: ZoneListItem) => {
          if (!isDefined(rowData.zoneType)) {
            return '';
          }
          const key = this.zoneTypeTranslationKeys[rowData.zoneType];
          return isDefined(key)
            ? this.translate.instant(key)
            : rowData.zoneType;
        },
        filterConfig: {
          type: 'multiselect',
          options: [
            {
              label: this.translate.instant(
                'ADMIN.ZONES.DETAILS.TYPES.LOCATION',
              ),
              value: 'location',
            },
            {
              label: this.translate.instant(
                'ADMIN.ZONES.DETAILS.TYPES.KEEP_IN',
              ),
              value: 'keepin',
            },
            {
              label: this.translate.instant('ADMIN.ZONES.DETAILS.TYPES.NO_GO'),
              value: 'nogo',
            },
            {
              label: this.translate.instant('ADMIN.ZONES.DETAILS.TYPES.ROUTE'),
              value: 'route',
            },
          ],
        },
      },
      {
        field: 'costCentre',
        header: this.translate.instant('ADMIN.ZONES.COLUMNS.COST_CENTRE'),
        valueGetter: (rowData: ZoneListItem) =>
          isDefined(rowData.costCentre?.name) ? rowData.costCentre?.name : '',
        filter: true,
        filterType: 'multiselect',
        filterMatchMode: 'in',
        filterConfig: {
          type: 'multiselect',
          options: [],
        },
      },
      {
        field: 'group',
        header: this.translate.instant('ADMIN.ZONES.COLUMNS.GROUP'),
        valueGetter: (rowData: ZoneListItem) =>
          isDefined(rowData.group?.name) ? rowData.group?.name : '',
        filter: true,
        filterType: 'multiselect',
        filterMatchMode: 'in',
        filterConfig: {
          type: 'multiselect',
          options: [],
        },
      },
      {
        field: 'state',
        header: this.translate.instant('ADMIN.ZONES.COLUMNS.STATE'),
        filter: true,
        filterType: 'multiselect',
        filterMatchMode: 'in',
        filterConfig: {
          type: 'multiselect',
          options: [
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.ACTIVE'),
              value: 'active',
            },
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.INACTIVE'),
              value: 'inactive',
            },
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.DELETED'),
              value: 'deleted',
            },
          ],
          defaultSelected: this.defaultStateValues,
        },
        transform: 'capitalize',
      },
      {
        field: 'modifiedDate',
        header: this.translate.instant('ADMIN.ZONES.COLUMNS.MODIFIED'),
        filter: false,
        valueGetter: (rowData: ZoneListItem) =>
          isDefined(rowData.modifiedDate)
            ? this.measurementDateTimeService.formatDateTime(
                this.measurementDateTimeService.createDateAssumingUtc(
                  rowData.modifiedDate,
                ),
                DATE_FORMATS.DATE_TIME_SECONDS_YMD,
              )
            : '',
      },
    ];
  }

  getFilters(): Record<string, FilterCriteria> {
    return this.filterState();
  }

  clearFilters(): void {
    this.filterState.set({
      state: {
        value: this.defaultStateValues,
        operator: 'in',
      },
    });
  }

  initialize(params: Record<string, string>): void {
    this.params = params;
    this.columns = this.buildColumns();
    this.loadFilterOptions();
  }

  getTitle(): string {
    return this.translate.instant('ADMIN.ZONES.TITLE');
  }

  getRequestParams(event?: TableLazyLoadEvent): DataGridParams {
    let sortField = 'name:asc'; // Default

    if (isDefined(event?.sortField)) {
      const sortOrder = event.sortOrder === 1 ? 'asc' : 'desc';
      sortField = `${event.sortField}:${sortOrder}`;
    }

    return {
      owner: this.params['clientId'],
      offset: isDefined(event?.first) ? event.first : 0,
      recurse: false,
      limit: isDefined(event?.rows) ? event.rows : DEFAULT_PAGE_SIZE,
      sortField: sortField,
      filters: this.rqlFilter(),
    };
  }

  onFilterChange(field: string, value: FilterValue): void {
    const actualField = this.fieldTransformations[field] || field;
    const column = this.columns.find((col) => col.field === field);

    if (Array.isArray(value)) {
      const newFilters = this.gridBaseService.handleFilters(
        this.filterState(),
        actualField,
        value,
        undefined,
        column?.filterMatchMode,
      );

      this.filterState.set(newFilters);
      return;
    }

    const newFilters = this.gridBaseService.handleFilters(
      this.filterState(),
      actualField,
      value,
      undefined,
      column?.filterMatchMode,
    );

    this.filterState.set(newFilters);
  }

  private loadFilterOptions(): void {
    combineLatest([
      this.entitiesService.listCostCentres(this.params['clientId']),
      this.entitiesService.listZoneGroups(this.params['clientId']),
    ])
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        catchError(() => {
          return EMPTY;
        }),
      )
      .subscribe(([costCentres, zoneGroups]) => {
        const costCentreColumn = this.columns.find(
          (col) => col.field === 'costCentre',
        );
        if (costCentreColumn?.filterConfig) {
          costCentreColumn.filterConfig.options = costCentres.items
            .map((costCentre) => ({
              label: costCentre.name ?? '',
              value: costCentre.id,
            }))
            .sort((a, b) => a.label.localeCompare(b.label));
        }

        const groupColumn = this.columns.find((col) => col.field === 'group');
        if (groupColumn?.filterConfig) {
          groupColumn.filterConfig.options = zoneGroups.items
            .map((group) => ({
              label: group.name ?? '',
              value: group.id,
            }))
            .sort((a, b) => a.label.localeCompare(b.label));
        }
      });
  }

  onAdd(): void {
    const clientId = this.params['clientId'];

    this.openGeofenceCreationDialog(clientId).subscribe();
  }

  openGeofenceCreationDialog(ownerId: string) {
    this.dialogRef = this.dialogService.open(GeofenceCreateWizardComponent, {
      header: this.translate.instant('SHARED.COMMON.WIZARD.TITLE', {
        entity: this.translate.instant('ADMIN.ENTITIES.ZONE'),
      }),
      baseZIndex: 10000,
      data: { ownerId: ownerId },
      position: 'top',
      modal: true,
    });

    return (this.dialogRef as DynamicDialogRef).onClose;
  }
}
