import { Injectable, computed, inject } from '@angular/core';

import { TableLazyLoadEvent } from 'primeng/table';

import {
  DataGridParams,
  DATE_FORMATS,
  TreeTableColumn,
  TreeTableConfiguration,
} from '../../../shared/models';
import { isDefined } from '../../../shared/utils';

import { CostCentreResponse } from '../../../api';
import { CostCentresDataAdapter } from '../services/adapters';
import { MeasurementDateTimeService } from '../../../shared/services/measurement-units/measurement-date-time.service';
import { DynamicDialogRef, DialogService } from 'primeng/dynamicdialog';
import { CostCentreCreateWizardComponent } from '../components/cost-centres/cost-centre-create-wizard/cost-centre-create-wizard.component';
import { take } from 'rxjs';
import { DEFAULT_LIST_SIZE } from '../../../core/models';
import { TranslateService } from '@ngx-translate/core';
import { LanguageService } from '../../../core/services/language.service';

@Injectable({ providedIn: 'root' })
export class CostCentresGridConfig implements TreeTableConfiguration<CostCentreResponse> {
  private readonly costCentresService = inject(CostCentresDataAdapter);
  private readonly measurementDateTimeService = inject(
    MeasurementDateTimeService,
  );
  private dialogRef: DynamicDialogRef | null = null;
  private readonly dialogService = inject(DialogService);
  private readonly translate = inject(TranslateService);
  private readonly languageService = inject(LanguageService);

  private params: Record<string, string> = { clientId: '' };

  entityType = 'cost-centres';
  columns: TreeTableColumn<CostCentreResponse>[] = this.buildColumns();
  readonly columnsSignal = computed(() => {
    this.languageService.currentLanguage();
    return this.buildColumns();
  });

  defaultVisibleColumns = ['name', 'modifiedDate'];

  dataService = this.costCentresService;

  private buildColumns(): TreeTableColumn<CostCentreResponse>[] {
    return [
      {
        field: 'name',
        header: this.translate.instant('ADMIN.COST_CENTRES.COLUMNS.NAME'),
        filterType: 'text',
      },
      {
        field: 'modifiedDate',
        header: this.translate.instant('ADMIN.COST_CENTRES.COLUMNS.MODIFIED'),
        valueGetter: (rowData: CostCentreResponse) =>
          isDefined(rowData?.entity?.modifiedDate)
            ? this.measurementDateTimeService.formatDateTime(
                this.measurementDateTimeService.createDateAssumingUtc(
                  rowData?.entity?.modifiedDate,
                ),
                DATE_FORMATS.DATE_TIME_SECONDS_YMD,
              )
            : '',
      },
    ];
  }

  initialize(params: Record<string, string>): void {
    this.params = params;
  }

  getTitle(): string {
    return this.translate.instant('ADMIN.COST_CENTRES.TITLE');
  }

  getRequestParams(event?: TableLazyLoadEvent): DataGridParams {
    // Add sorting support
    let sortField = 'name:asc'; // Default

    if (isDefined(event?.sortField) && event.sortField !== '') {
      const sortOrder = event.sortOrder === 1 ? 'asc' : 'desc';
      sortField = `${event.sortField}:${sortOrder}`;
    }

    return {
      owner: this.params['clientId'],
      offset: isDefined(event?.first) ? event.first : 0,
      recurse: false,
      limit: DEFAULT_LIST_SIZE,
      sortField: sortField,
    };
  }

  onAdd(): void {
    const clientId = this.params['clientId'];

    this.openCostCentreCreationDialog(clientId).pipe(take(1)).subscribe();
  }

  openCostCentreCreationDialog(ownerId: string) {
    this.dialogRef = this.dialogService.open(CostCentreCreateWizardComponent, {
      header: this.translate.instant('SHARED.COMMON.WIZARD.TITLE', {
        entity: this.translate.instant('ADMIN.ENTITIES.COST_CENTRE'),
      }),
      contentStyle: { overflow: 'auto' },
      baseZIndex: 10000,
      data: { ownerId: ownerId },
      position: 'top',
      modal: true,
    });

    return (this.dialogRef as DynamicDialogRef).onClose;
  }
}
