import {
  DestroyRef,
  Injectable,
  computed,
  inject,
  signal,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { tap } from 'rxjs';

import { TableLazyLoadEvent } from 'primeng/table';

import {
  DataGridParams,
  DATE_FORMATS,
  FilterCriteria,
  FilterValue,
  GridColumn,
  GridConfiguration,
  GridDataService,
} from '../../../shared/models';
import { EmailProvidersDataAdapter } from '../services/adapters/email-providers-data-adapter.service';
import { EmailProviderListItem, EntitiesService, IdName } from '../../../api';
import { UtilityService } from '../../../core/services/utility.service';
import { GridBaseService } from '../../../shared/services/grid-base.service';
import { DEFAULT_PAGE_SIZE } from '../../../core/models';
import { isDefined } from '../../../shared/utils';
import { DialogService, DynamicDialogRef } from 'primeng/dynamicdialog';
import { EmailProviderCreateWizardComponent } from '../components/email-providers/email-provider-create-wizard/email-provider-create-wizard.component';
import { MeasurementDateTimeService } from '../../../shared/services/measurement-units/measurement-date-time.service';
import { ApiSchemaService } from '../../../core/services/api-schema.service';
import { TranslateService } from '@ngx-translate/core';
import { LanguageService } from '../../../core/services/language.service';

@Injectable({
  providedIn: 'root',
})
export class EmailProvidersGridConfig implements GridConfiguration<EmailProviderListItem> {
  private readonly emailProvidersService = inject(EmailProvidersDataAdapter);
  private readonly entitiesService = inject(EntitiesService);
  private readonly utilityService = inject(UtilityService);
  private readonly gridBaseService = inject(GridBaseService);
  private readonly measurementDateTimeService = inject(
    MeasurementDateTimeService,
  );
  private readonly apiSchemaService = inject(ApiSchemaService);
  private readonly destroyRef = inject(DestroyRef);
  private readonly translate = inject(TranslateService);
  private readonly languageService = inject(LanguageService);

  private readonly defaultStateValues = [
    EmailProviderListItem.StateEnum.Active,
  ];
  private readonly filterState = signal<Record<string, FilterCriteria>>({
    state: {
      value: this.defaultStateValues,
      operator: 'in',
    },
  });
  private params: Record<string, string> = {};
  private readonly fieldTransformations: Record<string, string> = {
    type: 'type.id',
  };
  private dialogRef: DynamicDialogRef | null = null;
  private readonly dialogService = inject(DialogService);

  private readonly rqlFilter = computed(() =>
    this.utilityService.constructRqlFilter(this.filterState()),
  );

  entityType = 'email-providers';
  columns: GridColumn<EmailProviderListItem>[] = this.buildColumns();
  readonly columnsSignal = computed(() => {
    this.languageService.currentLanguage();
    return this.buildColumns();
  });

  dataService: GridDataService<EmailProviderListItem> =
    this.emailProvidersService;
  ownerId = '';

  private buildColumns(): GridColumn<EmailProviderListItem>[] {
    return [
      {
        field: 'name',
        header: this.translate.instant('ADMIN.EMAIL_PROVIDERS.COLUMNS.NAME'),
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
      },
      {
        field: 'type',
        header: this.translate.instant('ADMIN.EMAIL_PROVIDERS.COLUMNS.TYPE'),
        filter: true,
        filterType: 'toggle',
        filterMatchMode: 'in',
        filterConfig: {
          type: 'toggle',
          options: [],
        },
        valueGetter: (rowData: EmailProviderListItem) => {
          const typeValue = this.apiSchemaService.getEntityType<
            Record<string, unknown>,
            IdName
          >(rowData, 'emailprovider');
          return typeValue?.name ?? '';
        },
      },
      {
        field: 'state',
        header: this.translate.instant('ADMIN.EMAIL_PROVIDERS.COLUMNS.STATE'),
        filter: true,
        filterType: 'multiselect',
        filterMatchMode: 'in',
        filterConfig: {
          type: 'multiselect',
          options: [
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.ACTIVE'),
              value: EmailProviderListItem.StateEnum.Active,
            },
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.DELETED'),
              value: EmailProviderListItem.StateEnum.Deleted,
            },
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.SUSPENDED'),
              value: EmailProviderListItem.StateEnum.Suspended,
            },
          ],
          defaultSelected: this.defaultStateValues,
        },
        valueGetter: (rowData: EmailProviderListItem) =>
          isDefined(rowData.state)
            ? this.translate.instant(
                `SHARED.COMMON.STATUS.${rowData.state.toUpperCase()}`,
              )
            : '',
      },
      {
        field: 'modifiedDate',
        header: this.translate.instant(
          'ADMIN.EMAIL_PROVIDERS.COLUMNS.MODIFIED',
        ),
        filter: false,
        valueGetter: (rowData: EmailProviderListItem) =>
          isDefined(rowData.modifiedDate)
            ? this.measurementDateTimeService.formatDateTime(
                this.measurementDateTimeService.createDateAssumingUtc(
                  rowData.modifiedDate,
                ),
                DATE_FORMATS.DATE_TIME_SECONDS_YMD,
              )
            : '',
      },
    ];
  }

  private loadFilterOptions(): void {
    this.entitiesService
      .listEmailProviderTypes(this.ownerId)
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        tap((types) => {
          const typeColumn = this.columns.find((col) => col.field === 'type');
          if (typeColumn?.filterConfig) {
            typeColumn.filterConfig.options = types.items
              .map((type) => ({
                label: type.name ?? '',
                value: type.id,
              }))
              .sort((a, b) => a.label.localeCompare(b.label));
          }
        }),
      )
      .subscribe();
  }

  getFilters(): Record<string, FilterCriteria> {
    return this.filterState();
  }

  clearFilters(): void {
    this.filterState.set({});
  }

  initialize(params: Record<string, string>): void {
    this.params = params;
    if (isDefined(this.params['clientId'])) {
      this.ownerId = String(this.params['clientId']);
    } else if (isDefined(this.params['vendorId'])) {
      this.ownerId = String(this.params['vendorId']);
    } else if (isDefined(this.params['distributorId'])) {
      this.ownerId = String(this.params['distributorId']);
    }
    this.columns = this.buildColumns();
    this.loadFilterOptions();
  }

  getTitle(): string {
    return this.translate.instant('ADMIN.EMAIL_PROVIDERS.TITLE');
  }

  getRequestParams(event?: TableLazyLoadEvent): DataGridParams {
    return {
      owner: this.ownerId,
      offset: isDefined(event?.first) ? event.first : 0,
      recurse: false,
      limit: isDefined(event?.rows) ? event.rows : DEFAULT_PAGE_SIZE,
      sortField: 'name',
      filters: this.rqlFilter(),
    };
  }

  onFilterChange(field: string, value: FilterValue): void {
    const actualField = this.fieldTransformations[field] || field;
    const column = this.columns.find((col) => col.field === field);

    if (Array.isArray(value)) {
      const newFilters = this.gridBaseService.handleFilters(
        this.filterState(),
        actualField,
        value,
        undefined,
        column?.filterMatchMode,
      );

      this.filterState.set(newFilters);
      return;
    }

    const newFilters = this.gridBaseService.handleFilters(
      this.filterState(),
      actualField,
      value,
      undefined,
      column?.filterMatchMode,
    );

    this.filterState.set(newFilters);
  }

  onAdd(): void {
    this.openEmailProviderCreationDialog(this.ownerId)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe((createdEmailProvider) => {
        if (isDefined(createdEmailProvider)) {
          // Refresh your emailProvider list or take any other necessary actions
          // this.refreshEmailProviders();
        }
      });
  }

  openEmailProviderCreationDialog(ownerId: string) {
    this.dialogRef = this.dialogService.open(
      EmailProviderCreateWizardComponent,
      {
        header: this.translate.instant('SHARED.COMMON.WIZARD.TITLE', {
          entity: this.translate.instant('ADMIN.ENTITIES.EMAIL_PROVIDER'),
        }),
        contentStyle: { overflow: 'auto' },
        baseZIndex: 10000,
        data: { ownerId: ownerId },
        position: 'top',
        modal: true,
      },
    );

    return (this.dialogRef as DynamicDialogRef).onClose;
  }
}
