import { Injectable } from '@angular/core';
import { TreeTableColumn } from '../models';

@Injectable({ providedIn: 'root' })
export class CsvExportService {
  export<T>(columns: TreeTableColumn<T>[], rows: T[], filename: string): void {
    const exportCols = columns.filter((col) => col.exportable !== false);
    const header = exportCols.map((col) => this.escape(col.header)).join(',');
    const dataRows = rows.map((row) =>
      exportCols
        .map((col) => this.escape(String(this.resolveValue(col, row) ?? '')))
        .join(','),
    );

    const csv = [header, ...dataRows].join('\r\n');
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    a.click();
    URL.revokeObjectURL(url);
  }

  private resolveValue<T>(col: TreeTableColumn<T>, row: T): string | number {
    if (col.valueGetter) return col.valueGetter(row);

    const field = col.field as string;
    if (field.includes('.')) {
      return this.resolvePath(row as Record<string, unknown>, field);
    }
    return String((row as Record<string, unknown>)[field] ?? '');
  }

  private resolvePath(obj: Record<string, unknown>, path: string): string {
    const value = path.split('.').reduce<unknown>((acc, key) => {
      return acc != null && typeof acc === 'object'
        ? (acc as Record<string, unknown>)[key]
        : undefined;
    }, obj);
    return String(value ?? '');
  }

  private escape(value: string): string {
    if (/[,"\n\r]/.test(value)) {
      return `"${value.replace(/"/g, '""')}"`;
    }
    return value;
  }
}
