import { Injectable, computed, inject, signal } from '@angular/core';

import { TableLazyLoadEvent } from 'primeng/table';
import { EMPTY, Observable, expand, map, reduce, switchMap } from 'rxjs';

import {
  GridConfiguration,
  GridDataService,
  GridResponse,
  DataGridParams,
  GridColumn,
  FilterCriteria,
  FilterValue,
  DATE_FORMATS,
} from '../../../shared/models';
import { XlsxExportService } from '../../../shared/services/xlsx-export.service';
import { UtilityService } from '../../../core/services/utility.service';
import { GridBaseService } from '../../../shared/services/grid-base.service';
import { isDefined, isString } from '../../../shared/utils';
import { DevicesDataAdapter } from '../services/adapters';
import { DeviceListItem } from '../../../api';
import { DEFAULT_PAGE_SIZE } from '../../../core/models';
import { DynamicDialogRef, DialogService } from 'primeng/dynamicdialog';
import { DeviceCreateWizardComponent } from '../components/device/device-create-wizard/device-create-wizard.component';
import { MeasurementDateTimeService } from '../../../shared/services/measurement-units/measurement-date-time.service';
import { TranslateService } from '@ngx-translate/core';
import { LanguageService } from '../../../core/services/language.service';

/** Page size used when draining every page for a full CSV export. */
const EXPORT_PAGE_SIZE = 200;

@Injectable({
  providedIn: 'root',
})
export class DevicesGridConfig implements GridConfiguration<DeviceListItem> {
  private readonly devicesService = inject(DevicesDataAdapter);
  private readonly xlsxExportService = inject(XlsxExportService);
  private readonly utilityService = inject(UtilityService);
  private readonly gridBaseService = inject(GridBaseService);
  private dialogRef: DynamicDialogRef | null = null;
  private readonly dialogService = inject(DialogService);
  private readonly measurementDateTimeService = inject(
    MeasurementDateTimeService,
  );
  private readonly translate = inject(TranslateService);
  private readonly languageService = inject(LanguageService);

  private readonly defaultStateValues = [
    DeviceListItem.StateEnum.Active,
    DeviceListItem.StateEnum.Inactive,
    DeviceListItem.StateEnum.Suspended,
  ];
  private readonly filterState = signal<Record<string, FilterCriteria>>({
    state: {
      value: this.defaultStateValues,
      operator: 'in',
    },
  });
  private params: Record<string, string> = { clientId: '' };

  private readonly rqlFilter = computed(() =>
    this.utilityService.constructRqlFilter(this.filterState()),
  );
  private readonly fieldTransformations: Record<string, string> = {
    ['01usv']: 'fields.01usv',
    ['02udr']: 'fields.02udr',
    simCard: 'simcard.name',
    asset: 'asset.name',
    configProfile: 'configProfile.name',
    deviceType: 'deviceType.name',
  };

  entityType = 'devices';
  selectionMode = 'multiple' as const;
  columns: GridColumn<DeviceListItem>[] = this.buildColumns();
  readonly columnsSignal = computed(() => {
    this.languageService.currentLanguage();
    return this.buildColumns();
  });

  dataService: GridDataService<DeviceListItem> = this.devicesService;

  private buildColumns(): GridColumn<DeviceListItem>[] {
    return [
      {
        field: 'name',
        header: this.translate.instant('ADMIN.DEVICES.COLUMNS.NAME'),
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
      },
      {
        field: 'deviceType',
        header: this.translate.instant('ADMIN.DEVICES.COLUMNS.DEVICE_TYPE'),
        valueGetter: (rowData: DeviceListItem) =>
          isDefined(rowData.deviceType?.name) ? rowData.deviceType?.name : '',
        filter: true,
        filterType: 'multiselect',
        filterMatchMode: 'in',
        filterConfig: {
          type: 'multiselect',
          options: [],
        },
      },
      {
        field: 'state',
        header: this.translate.instant('ADMIN.DEVICES.COLUMNS.STATE'),
        valueGetter: (rowData: DeviceListItem) =>
          isDefined(rowData.state)
            ? this.translate.instant(
                `SHARED.COMMON.STATUS.${rowData.state.toUpperCase()}`,
              )
            : '',
        filter: true,
        filterType: 'multiselect',
        filterMatchMode: 'in',
        filterConfig: {
          type: 'multiselect',
          options: [
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.ACTIVE'),
              value: DeviceListItem.StateEnum.Active,
            },
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.DELETED'),
              value: DeviceListItem.StateEnum.Deleted,
            },
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.INACTIVE'),
              value: DeviceListItem.StateEnum.Inactive,
            },
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.SUSPENDED'),
              value: DeviceListItem.StateEnum.Suspended,
            },
          ],
          defaultSelected: this.defaultStateValues,
        },
        transform: 'capitalize',
      },
      {
        field: 'asset',
        header: this.translate.instant('ADMIN.DEVICES.COLUMNS.ASSET'),
        valueGetter: (rowData: DeviceListItem) =>
          isDefined(rowData.asset?.name) ? rowData.asset?.name : '',
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
      },
      {
        field: 'simCard',
        header: this.translate.instant('ADMIN.DEVICES.COLUMNS.SIM_CARD'),
        valueGetter: (rowData: DeviceListItem) =>
          isDefined(rowData.simcard?.name) ? rowData.simcard?.name : '',
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
      },
      {
        field: 'configProfile',
        header: this.translate.instant('ADMIN.DEVICES.COLUMNS.CONFIG_PROFILE'),
        valueGetter: (rowData: DeviceListItem) =>
          isDefined(rowData.configProfile?.name)
            ? rowData.configProfile?.name
            : '',
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
      },
      {
        field: '01usv',
        header: this.translate.instant('ADMIN.DEVICES.COLUMNS.DEVICE_SERIAL'),
        valueGetter: (rowData: DeviceListItem) =>
          isDefined(rowData.fields?.['01usv']) &&
          isString(rowData.fields?.['01usv'])
            ? rowData.fields?.['01usv']
            : '',
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
      },
      {
        field: '02udr',
        header: this.translate.instant('ADMIN.DEVICES.COLUMNS.DEVICE_REMARKS'),
        valueGetter: (rowData: DeviceListItem) =>
          isDefined(rowData.fields?.['02udr']) &&
          isString(rowData.fields?.['02udr'])
            ? rowData.fields?.['02udr']
            : '',
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
      },
      {
        field: 'modifiedDate',
        header: this.translate.instant('ADMIN.DEVICES.COLUMNS.MODIFIED'),
        filter: false,
        valueGetter: (rowData: DeviceListItem) =>
          isDefined(rowData['modifiedDate'])
            ? this.measurementDateTimeService.formatDateTime(
                this.measurementDateTimeService.createDateAssumingUtc(
                  rowData['modifiedDate'],
                ),
                DATE_FORMATS.DATE_TIME_SECONDS_YMD,
              )
            : '',
      },
    ];
  }

  getFilters(): Record<string, FilterCriteria> {
    return this.filterState();
  }

  clearFilters(): void {
    this.filterState.set({
      state: {
        value: this.defaultStateValues,
        operator: 'in',
      },
    });
  }

  initialize(params: Record<string, string>): void {
    this.params = params;
  }

  getTitle(): string {
    return this.translate.instant('ADMIN.DEVICES.TITLE');
  }

  getRequestParams(event?: TableLazyLoadEvent): DataGridParams {
    let sortField = 'name:asc'; // Default

    if (isDefined(event?.sortField)) {
      const sortOrder = event.sortOrder === 1 ? 'asc' : 'desc';
      sortField = `${event.sortField}:${sortOrder}`;
    }

    return {
      owner: this.params['clientId'],
      offset: isDefined(event?.first) ? event.first : 0,
      recurse: false,
      limit: isDefined(event?.rows) ? event.rows : DEFAULT_PAGE_SIZE,
      sortField: sortField,
      filters: this.rqlFilter(),
    };
  }

  /**
   * Export every device matching the current filters/sort — not just the page
   * rendered in the grid. The grid holds a single server-fetched page in memory,
   * so PrimeNG's native export would truncate the file to that page and, because
   * it ignores column `valueGetter`s, emit `[object Object]` for object-valued
   * columns (Type, Asset, SIM Card, Config Profile). Instead we sweep all pages
   * and hand the rows to {@link XlsxExportService}, which resolves each cell
   * through its `valueGetter`.
   *
   * Exports as `.xlsx` rather than CSV so that long numeric identifiers (IMEIs,
   * SIM serials) open correctly in Excel: CSV values get converted to scientific
   * notation on open, and modern Excel ignores the in-band text hints that used
   * to prevent that.
   *
   * Returns an `Observable<void>` that completes once the file is generated (or
   * errors if a fetch fails) so the container can drive its loading indicator.
   */
  onExport(): Observable<void> {
    const columns = this.columnsSignal();
    const date = new Date().toISOString().slice(0, 10);

    return this.fetchAllDevicesForExport().pipe(
      switchMap((devices) =>
        this.xlsxExportService.export(
          columns,
          devices,
          `devices-${date}.xlsx`,
          'Devices',
        ),
      ),
    );
  }

  /**
   * Fetch every device for the current client/filters by draining all pages,
   * reusing {@link getRequestParams} so the export honours the same
   * owner/sort/filters as the on-screen grid.
   */
  private fetchAllDevicesForExport(): Observable<DeviceListItem[]> {
    const baseParams = this.getRequestParams();

    return this.fetchAllPages((offset, limit) =>
      this.devicesService.getList({ ...baseParams, offset, limit }),
    );
  }

  /**
   * Drain every page of a paginated list query, accumulating all items in order.
   * Stops when a page comes back empty or the reported total `count` has been
   * reached, so it is resilient to a backend that caps the page size below the
   * requested limit.
   */
  private fetchAllPages(
    query: (
      offset: number,
      limit: number,
    ) => Observable<GridResponse<DeviceListItem>>,
  ): Observable<DeviceListItem[]> {
    const fetchFrom = (
      offset: number,
    ): Observable<{
      items: DeviceListItem[];
      nextOffset: number;
      count: number;
    }> =>
      query(offset, EXPORT_PAGE_SIZE).pipe(
        map((response) => {
          const items = response.items ?? [];
          return {
            items,
            nextOffset: offset + items.length,
            count: response.count ?? 0,
          };
        }),
      );

    return fetchFrom(0).pipe(
      expand((page) =>
        page.items.length > 0 && page.nextOffset < page.count
          ? fetchFrom(page.nextOffset)
          : EMPTY,
      ),
      reduce(
        (acc: DeviceListItem[], page) => acc.concat(page.items),
        [] as DeviceListItem[],
      ),
    );
  }

  onFilterChange(field: string, value: FilterValue): void {
    const actualField = this.fieldTransformations[field] || field;
    const column = this.columns.find((col) => col.field === field);

    if (Array.isArray(value)) {
      const newFilters = this.gridBaseService.handleFilters(
        this.filterState(),
        actualField,
        value,
        undefined,
        column?.filterMatchMode,
      );

      this.filterState.set(newFilters);
      return;
    }

    const newFilters = this.gridBaseService.handleFilters(
      this.filterState(),
      actualField,
      value,
      undefined,
      column?.filterMatchMode,
    );

    this.filterState.set(newFilters);
  }

  onAdd(): void {
    const clientId = this.params['clientId'];

    this.openDeviceCreationDialog(clientId).subscribe();
  }

  openDeviceCreationDialog(ownerId: string) {
    this.dialogRef = this.dialogService.open(DeviceCreateWizardComponent, {
      header: this.translate.instant('SHARED.COMMON.WIZARD.TITLE', {
        entity: this.translate.instant('ADMIN.ENTITIES.DEVICE'),
      }),
      baseZIndex: 10000,
      data: {
        ownerId: ownerId,
      },
      position: 'top',
      modal: true,
    });

    return (this.dialogRef as DynamicDialogRef).onClose;
  }

  onBulkImport(): void {
    const clientId = this.params['clientId'];

    this.openBulkImportDialog(clientId)
      .then((obs) => obs.subscribe())
      .catch(console.error);
  }

  async openBulkImportDialog(ownerId: string) {
    const { BulkImportDialogComponent } =
      await import('../components/shared/bulk-import-dialog/bulk-import-dialog.component');

    this.dialogRef = this.dialogService.open(BulkImportDialogComponent, {
      header: this.translate.instant('ADMIN.DEVICES.BULK_IMPORT_TITLE'),
      baseZIndex: 10000,
      data: {
        ownerId: ownerId,
      },
      position: 'top',
      modal: true,
      width: '800px',
    });

    return (this.dialogRef as DynamicDialogRef).onClose;
  }
}
