import {
  DestroyRef,
  Injectable,
  computed,
  inject,
  signal,
} from '@angular/core';

import { TableLazyLoadEvent } from 'primeng/table';

import {
  GridConfiguration,
  GridDataService,
  DataGridParams,
  GridColumn,
  FilterCriteria,
  FilterValue,
  DATE_FORMATS,
} from '../../../shared/models';
import { UtilityService } from '../../../core/services/utility.service';
import { GridBaseService } from '../../../shared/services/grid-base.service';
import { isDefined, isNullOrUndefined } from '../../../shared/utils';
import { VendorsDataAdapter } from '../services/adapters';
import { AccountsService, VendorListItem } from '../../../api';
import { DEFAULT_PAGE_SIZE } from '../../../core/models';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { catchError, EMPTY } from 'rxjs';
import { MeasurementDateTimeService } from '../../../shared/services/measurement-units/measurement-date-time.service';
import { DynamicDialogRef, DialogService } from 'primeng/dynamicdialog';
import { DistributorVendorCreateWizardComponent } from '../components/distributor-vendors/distributor-vendor-create-wizard/distributor-vendor-create-wizard.component';
import { BroadcastEventMessageService } from '../services/broadcast-event-messages.service';
import { TranslateService } from '@ngx-translate/core';
import { LanguageService } from '../../../core/services/language.service';

@Injectable({
  providedIn: 'root',
})
export class VendorsGridConfig implements GridConfiguration<VendorListItem> {
  private readonly vendorsService = inject(VendorsDataAdapter);
  private readonly utilityService = inject(UtilityService);
  private readonly gridBaseService = inject(GridBaseService);
  private readonly accountsService = inject(AccountsService);
  private readonly measurementDateTimeService = inject(
    MeasurementDateTimeService,
  );
  private dialogRef: DynamicDialogRef | null = null;
  private readonly dialogService = inject(DialogService);
  private readonly broadcastService = inject(BroadcastEventMessageService);
  private readonly destroyRef = inject(DestroyRef);
  private readonly translate = inject(TranslateService);
  private readonly languageService = inject(LanguageService);

  private readonly defaultStateValues = [
    VendorListItem.StateEnum.Active,
    VendorListItem.StateEnum.Inactive,
    VendorListItem.StateEnum.Suspended,
  ];
  private readonly filterState = signal<Record<string, FilterCriteria>>({
    state: {
      value: this.defaultStateValues,
      operator: 'in',
    },
  });
  private params: Record<string, string> = { distributorId: '' };

  private readonly rqlFilter = computed(() =>
    this.utilityService.constructRqlFilter(this.filterState()),
  );
  private readonly fieldTransformations: Record<string, string> = {
    type: 'type.id',
  };
  entityType = 'vendors';
  columns: GridColumn<VendorListItem>[] = this.buildColumns();
  readonly columnsSignal = computed(() => {
    this.languageService.currentLanguage();
    return this.buildColumns();
  });

  dataService: GridDataService<VendorListItem> = this.vendorsService;
  vendorGroupTypes: { label: string; value: string }[] = [];

  private buildColumns(): GridColumn<VendorListItem>[] {
    return [
      {
        field: 'name',
        header: this.translate.instant('ADMIN.VENDORS.COLUMNS.NAME'),
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
      },
      {
        field: 'website',
        header: this.translate.instant('ADMIN.VENDORS.COLUMNS.WEBSITE'),
        filter: true,
        filterType: 'text',
        filterMatchMode: 'contains',
      },
      {
        field: 'group',
        header: this.translate.instant('ADMIN.VENDORS.COLUMNS.GROUP'),
        valueGetter: (rowData: VendorListItem) => {
          if (isNullOrUndefined(rowData.group))
            return this.translate.instant('SHARED.COMMON.NONE');

          const value = this.vendorGroupTypes.find(
            (group) => group.value === rowData.group,
          )?.label;
          return value ?? this.translate.instant('SHARED.COMMON.NONE');
        },
        filter: true,
        filterType: 'multiselect',
        filterMatchMode: 'in',
        filterConfig: {
          type: 'multiselect',
          options: [],
        },
      },
      {
        field: 'state',
        header: this.translate.instant('ADMIN.VENDORS.COLUMNS.STATE'),
        valueGetter: (rowData: VendorListItem) =>
          isDefined(rowData.state)
            ? this.translate.instant(
                `SHARED.COMMON.STATUS.${rowData.state.toUpperCase()}`,
              )
            : '',
        filter: true,
        filterType: 'multiselect',
        filterMatchMode: 'in',
        filterConfig: {
          type: 'multiselect',
          options: [
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.ACTIVE'),
              value: VendorListItem.StateEnum.Active,
            },
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.DELETED'),
              value: VendorListItem.StateEnum.Deleted,
            },
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.INACTIVE'),
              value: VendorListItem.StateEnum.Inactive,
            },
            {
              label: this.translate.instant('SHARED.COMMON.STATUS.SUSPENDED'),
              value: VendorListItem.StateEnum.Suspended,
            },
          ],
          defaultSelected: this.defaultStateValues,
        },
        transform: 'capitalize',
      },
      {
        field: 'clients',
        header: this.translate.instant('ADMIN.VENDORS.COLUMNS.CLIENT'),
        valueGetter: (rowData: VendorListItem) =>
          isDefined(rowData.counts?.['client'])
            ? rowData.counts?.['client']
            : 0,
      },
      {
        field: 'assets',
        header: this.translate.instant('ADMIN.VENDORS.COLUMNS.ASSET'),
        valueGetter: (rowData: VendorListItem) =>
          isDefined(rowData.counts?.['asset']) ? rowData.counts?.['asset'] : 0,
      },
      {
        field: 'devices',
        header: this.translate.instant('ADMIN.VENDORS.COLUMNS.DEVICE'),
        valueGetter: (rowData: VendorListItem) =>
          isDefined(rowData.counts?.['device'])
            ? rowData.counts?.['device']
            : 0,
      },
      {
        field: 'companion-camera',
        header: this.translate.instant(
          'ADMIN.VENDORS.COLUMNS.COMPANION_CAMERA',
        ),
        valueGetter: (rowData: VendorListItem) =>
          isDefined(rowData.counts?.['companionCameraDevice'])
            ? rowData.counts?.['companionCameraDevice']
            : 0,
      },
      {
        field: 'users',
        header: this.translate.instant('ADMIN.VENDORS.COLUMNS.USER'),
        valueGetter: (rowData: VendorListItem) =>
          isDefined(rowData.counts?.['user']) ? rowData.counts?.['user'] : 0,
      },
      {
        field: 'modifiedDate',
        header: this.translate.instant('ADMIN.VENDORS.COLUMNS.MODIFIED'),
        filter: false,
        valueGetter: (rowData: VendorListItem) =>
          isDefined(rowData.modifiedDate)
            ? this.measurementDateTimeService.formatDateTime(
                this.measurementDateTimeService.createDateAssumingUtc(
                  rowData.modifiedDate,
                ),
                DATE_FORMATS.DATE_TIME_SECONDS_YMD,
              )
            : '',
      },
    ];
  }

  getFilters(): Record<string, FilterCriteria> {
    return this.filterState();
  }

  clearFilters(): void {
    this.filterState.set({
      state: {
        value: this.defaultStateValues,
        operator: 'in',
      },
    });
  }

  initialize(params: Record<string, string>): void {
    this.params = params;
    this.loadFilterOptions();
  }

  getTitle(): string {
    return this.translate.instant('ADMIN.VENDORS.TITLE');
  }

  getRequestParams(event?: TableLazyLoadEvent): DataGridParams {
    // Add sorting support
    let sortField = 'name:asc'; // Default

    if (isDefined(event?.sortField)) {
      const sortOrder = event.sortOrder === 1 ? 'asc' : 'desc';
      sortField = `${event.sortField}:${sortOrder}`;
    }

    return {
      owner: this.params['distributorId'],
      offset: isDefined(event?.first) ? event.first : 0,
      recurse: false,
      limit: isDefined(event?.rows) ? event.rows : DEFAULT_PAGE_SIZE,
      sortField: sortField,
      filters: this.rqlFilter(),
      counts: 'client,asset,device,companion-camera,user',
    };
  }

  onFilterChange(field: string, value: FilterValue): void {
    const actualField = this.fieldTransformations[field] || field;
    const column = this.columns.find((col) => col.field === field);

    const newFilters = this.gridBaseService.handleFilters(
      this.filterState(),
      actualField,
      value,
      undefined,
      column?.filterMatchMode,
    );

    this.filterState.set(newFilters);

    // If state filter changes, notify the tree to refresh with appropriate filter
    if (field === 'state') {
      const includeDeleted =
        Array.isArray(value) &&
        value.includes(VendorListItem.StateEnum.Deleted);

      // Broadcast filter change event for tree
      this.broadcastService.broadcast('vendor-filter-changed', {
        distributorId: this.params['distributorId'],
        includeDeleted,
      });
    }
  }

  private loadFilterOptions(): void {
    this.accountsService
      .listCompanyGroups(this.params['distributorId'])
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        catchError(() => {
          return EMPTY;
        }),
      )
      .subscribe((groups) => {
        const typeColumn = this.columns.find((col) => col.field === 'group');
        if (typeColumn?.filterConfig) {
          this.vendorGroupTypes = groups.items
            .map((type) => ({
              label: type.name ?? '',
              value: type.id,
            }))
            .sort((a, b) => a.label.localeCompare(b.label));
          typeColumn.filterConfig.options = this.vendorGroupTypes;
        }
      });
  }

  onAdd(): void {
    const ownerId = this.params['distributorId'];

    this.openVendorCreationDialog(ownerId).subscribe();
  }

  openVendorCreationDialog(ownerId: string) {
    this.dialogRef = this.dialogService.open(
      DistributorVendorCreateWizardComponent,
      {
        header: this.translate.instant('SHARED.COMMON.WIZARD.TITLE', {
          entity: this.translate.instant('ADMIN.ENTITIES.VENDOR'),
        }),
        contentStyle: { overflow: 'auto' },
        baseZIndex: 10000,
        data: { ownerId: ownerId },
        position: 'top',
        modal: true,
      },
    );

    return (this.dialogRef as DynamicDialogRef).onClose;
  }
}
